INSERT INTO `en_examples` VALUES (61,48,'I am a student.','Tôi là một sinh viên.','2026-01-16 05:50:24','2026-01-16 05:50:24'),(62,49,'You are my friend.','Bạn là bạn của tôi.','2026-01-16 05:50:24','2026-01-16 05:50:24'),(63,50,'He works here.','Anh ấy làm việc ở đây.','2026-01-16 05:50:24','2026-01-16 05:50:24'),(64,51,'She is very kind.','Cô ấy rất tốt bụng.','2026-01-16 05:50:24','2026-01-16 05:50:24'),(65,52,'It is my phone.','Đó là điện thoại của tôi.','2026-01-16 05:50:24','2026-01-16 05:50:24'),(66,53,'We are ready.','Chúng tôi đã sẵn sàng.','2026-01-16 05:50:24','2026-01-16 05:50:24'),(67,54,'They are at home.','Họ đang ở nhà.','2026-01-16 05:50:24','2026-01-16 05:50:24'),(68,55,'She helps me.','Cô ấy giúp tôi.','2026-01-16 05:50:24','2026-01-16 05:50:24'),(69,56,'I know him.','Tôi biết anh ấy.','2026-01-16 05:50:24','2026-01-16 05:50:24'),(70,57,'I see her.','Tôi nhìn thấy cô ấy.','2026-01-16 05:50:24','2026-01-16 05:50:24'),(71,58,'They invite us.','Họ mời chúng tôi.','2026-01-16 05:50:24','2026-01-16 05:50:24'),(72,59,'I like them.','Tôi thích họ.','2026-01-16 05:50:24','2026-01-16 05:50:24'),(73,60,'This is my bag.','Đây là cặp của tôi.','2026-01-16 05:50:24','2026-01-16 05:50:24'),(74,61,'Is this your book?','Đây có phải sách của bạn không?','2026-01-16 05:50:24','2026-01-16 05:50:24'),(75,62,'That is his car.','Đó là xe của anh ấy.','2026-01-16 05:50:24','2026-01-16 05:50:24'),(76,63,'This is our house.','Đây là nhà của chúng tôi.','2026-01-16 05:50:24','2026-01-16 05:50:24'),(77,64,'Their teacher is nice.','Giáo viên của họ rất tốt.','2026-01-16 05:50:24','2026-01-16 05:50:24'),(78,65,'This is easy.','Cái này dễ.','2026-01-16 05:50:24','2026-01-16 05:50:24'),(79,66,'That looks good.','Cái kia trông đẹp.','2026-01-16 05:50:24','2026-01-16 05:50:24'),(99,86,'He calls me.','Anh ấy gọi cho tôi.','2026-01-16 06:03:57','2026-01-16 06:03:57'),(100,87,'She likes him.','Cô ấy thích anh ấy.','2026-01-16 06:03:57','2026-01-16 06:03:57'),(101,88,'He talks to her.','Anh ấy nói chuyện với cô ấy.','2026-01-16 06:03:57','2026-01-16 06:03:57'),(102,89,'She helps us.','Cô ấy giúp chúng tôi.','2026-01-16 06:03:57','2026-01-16 06:03:57'),(103,90,'We meet them.','Chúng tôi gặp họ.','2026-01-16 06:03:57','2026-01-16 06:03:57'),(104,91,'My phone is new.','Điện thoại của tôi mới.','2026-01-16 06:03:57','2026-01-16 06:03:57'),(105,92,'Is this your pen?','Đây có phải bút của bạn không?','2026-01-16 06:03:57','2026-01-16 06:03:57'),(106,93,'His house is big.','Nhà của anh ấy lớn.','2026-01-16 06:03:57','2026-01-16 06:03:57'),(107,94,'Our teacher is kind.','Giáo viên của chúng tôi tốt bụng.','2026-01-16 06:03:57','2026-01-16 06:03:57'),(108,95,'Their bags are heavy.','Túi của họ nặng.','2026-01-16 06:03:57','2026-01-16 06:03:57'),(109,96,'This book is good.','Quyển sách này hay.','2026-01-16 06:03:57','2026-01-16 06:03:57'),(110,97,'That building is tall.','Toà nhà kia cao.','2026-01-16 06:03:57','2026-01-16 06:03:57'),(111,98,'I like coffee.','Tôi thích cà phê.','2026-01-16 06:04:21','2026-01-16 06:04:21'),(112,99,'You are happy.','Bạn đang vui.','2026-01-16 06:04:21','2026-01-16 06:04:21'),(113,100,'He is tall.','Anh ấy cao.','2026-01-16 06:04:21','2026-01-16 06:04:21'),(114,101,'She likes music.','Cô ấy thích âm nhạc.','2026-01-16 06:04:21','2026-01-16 06:04:21'),(115,102,'It is raining.','Trời đang mưa.','2026-01-16 06:04:21','2026-01-16 06:04:21'),(116,103,'We study English.','Chúng tôi học tiếng Anh.','2026-01-16 06:04:21','2026-01-16 06:04:21'),(117,104,'They are friends.','Họ là bạn bè.','2026-01-16 06:04:21','2026-01-16 06:04:21');
