INSERT INTO `jp_example_exercises` VALUES (1,1,'fill_in_blank','事故で腕の骨が（　）。',1,'‘折れる’ là đáp án đúng vì có nghĩa \'bị gãy\'.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(2,2,'fill_in_blank','彼は木の枝を（　）。',1,'‘折る’ là đáp án đúng vì có nghĩa \'làm gãy, bẻ\'.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(3,3,'fill_in_blank','人が（　）ている。',1,'‘倒れる’ là đáp án đúng vì có nghĩa \'ngã, đổ\'.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(4,4,'fill_in_blank','ボーリングのピンを全部（　）。',1,'‘倒す’ là đáp án đúng vì có nghĩa \'làm đổ\'.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(5,5,'fill_in_blank','大切な服が（　）。',1,'‘破れる’ là đáp án đúng vì có nghĩa \'bị rách\'.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(6,6,'fill_in_blank','紙を（　）てゴミ箱に捨てる。',1,'‘破る’ là đáp án đúng vì có nghĩa \'xé rách\'.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(7,7,'fill_in_blank','次の交差点を左に（　）てください。',1,'‘曲がる’ là đáp án đúng vì có nghĩa \'rẽ, cong\'.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(8,8,'fill_in_blank','ひざが痛くて（　）られない。',1,'‘曲げる’ là đáp án đúng vì có nghĩa \'gập, bẻ\'.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(9,9,'fill_in_blank','シャツのボタンが（　）。',1,'‘外れる’ là đáp án đúng vì có nghĩa \'bị tuột\'.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(10,10,'fill_in_blank','学校を（　）します。',1,'‘学校’ là từ đúng vì có nghĩa \'trường học\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(11,11,'fill_in_blank','先生を（　）します。',1,'‘先生’ là từ đúng vì có nghĩa \'giáo viên\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(12,12,'fill_in_blank','学生を（　）します。',1,'‘学生’ là từ đúng vì có nghĩa \'học sinh\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(13,13,'fill_in_blank','日本を（　）します。',1,'‘日本’ là từ đúng vì có nghĩa \'Nhật Bản\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(14,14,'fill_in_blank','友達を（　）します。',1,'‘友達’ là từ đúng vì có nghĩa \'bạn bè\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(15,15,'fill_in_blank','食べるを（　）します。',1,'‘食べる’ là từ đúng vì có nghĩa \'ăn\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(16,16,'fill_in_b