DROP TABLE IF EXISTS `jp_examples`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `jp_examples` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `jp_word_id` bigint unsigned NOT NULL,
  `sentence_jp` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `sentence_hira` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `sentence_romaji` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `sentence_vi` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `jp_examples_jp_word_id_foreign` (`jp_word_id`),
  CONSTRAINT `jp_examples_jp_word_id_foreign` FOREIGN KEY (`jp_word_id`) REFERENCES `jp_words` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2897 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

