INSERT INTO `jp_examples` VALUES (1,1,'事故で腕の骨が折れた。','じこでうでのほねがおれた。','Jiko de ude no hone ga oreta.','Xương cánh tay bị gãy do tai nạn.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(2,2,'彼は木の枝を折る。','かれはきのえだをおる。','Kare wa ki no eda o oru.','Bẻ cành cây xuống.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(3,3,'人が倒れている。','ひとがたおれている。','Hito ga taorete iru.','Người bị ngất (ngã xuống).','2025-08-25 10:36:16','2025-08-25 10:36:16'),(4,4,'ボーリングのピンを全部倒した。','ぼーりんぐのぴんをぜんぶたおした。','Booringu no pin o zenbu taoshita.','Ném đổ hết các chai bowling.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(5,5,'大切な服が破れた。','たいせつなふくがやぶれた。','Taisetsu na fuku ga yabureta.','Bộ quần áo mà tôi trân trọng đã bị rách.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(6,6,'紙を破ってゴミ箱に捨てる。','かみをやぶってごみばこにすてる。','Kami o yabutte gomibako ni suteru.','Xé giấy rồi vứt đi.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(7,7,'次の交差点を左に曲がってください。','つぎのこうさてんをひだりにまがってください。','Tsugi no kousaten o hidari ni magatte kudasai.','Hãy rẽ trái ở ngã tư tiếp theo.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(8,8,'ひざが痛くて曲げられない。','ひざがいたくてまげられない。','Hiza ga itakute magerarenai.','Đầu gối bị đau nên không gập lại được.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(9,9,'シャツのボタンが外れる。','しゃつのぼたんがはずれる。','Shatsu no botan ga hazureru.','Cúc áo bị tuột ra.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(10,10,'学校を勉強します。','がっこうをべんきょうします。','gakkou o benkyou shimasu.','Tôi học từ \'trường học\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(11,11,'先生を勉強します。','せんせいをべんきょうします。','sensei o benkyou shimasu.','Tôi học từ \'giáo viên\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(12,12,'学生を勉強します。','がくせいをべんきょうします。','gakusei o benkyou shimasu.','Tôi học từ \'học sinh\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(13,13,'日本を勉強します。','にほんをべんきょうします。','nihon o benkyou shimasu.','Tôi học từ \'Nhật Bản\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(14,14,'友達を勉強します。','ともだちをべんきょうします。','tomodachi o benkyou shimasu.','Tôi học từ \'bạn bè\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(15,15,'食べるを勉強します。','たべるをべんきょうします。','taberu o benkyou shimasu.','Tôi học từ \'ăn\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(16,16,'飲むを勉強します。','のむをべんきょうします。','nomu o benkyou shimasu.','Tôi học từ \'uống\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(17,17,'買うを勉強します。','かうをべんきょうします。','kau o benkyou shimasu.','Tôi học từ \'mua\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(18,18,'行くを勉強します。','いくをべんきょうします。','iku o benkyou shimasu.','Tôi học từ \'đi\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(19,19,'来るを勉強します。','くるをべんきょうします。','kuru o benkyou shimasu.','Tôi học từ \'đến\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(20,20,'話すを勉強します。','はなすをべんきょうします。','hanasu o benkyou shimasu.','Tôi học từ \'nói chuyện\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(21,21,'聞くを勉強します。','きくをべんきょうします。','kiku o benkyou shimasu.','Tôi học từ \'nghe\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(22,22,'見るを勉強します。','みるをべんきょうします。','miru o benkyou shimasu.','Tôi học từ \'xem, nhìn\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(23,23,'書くを勉強します。','かくをべんきょうします。','kaku o benkyou shimasu.','Tôi học từ \'viết\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(24,24,'読むを勉強します。','よむをべんきょうします。','yomu o benkyou shimasu.','Tôi học từ \'đọc\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(25,25,'立つを勉強します。','たつをべんきょうします。','tatsu o benkyou shimasu.','Tôi học từ \'đứng\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(26,26,'寝るを勉強します。','ねるをべんきょうします。','neru o benkyou shimasu.','Tôi học từ \'ngủ\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(27,27,'起きるを勉強します。','おきるをべんきょうします。','okiru o benkyou shimasu.','Tôi học từ \'thức dậy\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(28,28,'帰るを勉強します。','かえるをべんきょうします。','kaeru o benkyou shimasu.','Tôi học từ \'về\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(29,29,'働くを勉強します。','はたらくをべんきょうします。','hataraku o benkyou shimasu.','Tôi học từ \'làm việc\'.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(30,30,'電車のドアが閉じた。','でんしゃのどあがとじた。','Densha no doa ga toji ta.','Cửa tàu đã đóng lại.','2025-08-26 22:37:59','2025-08-26 22:37:59'),(31,31,'津波からドアの後ろに隠れている。','つなみからどあのうしろにかくれている。','Tsunami kara doa no ushiro ni kakurete iru.','Ai đó đang nấp sau cánh cửa.','2025-08-26 22:37:59','2025-08-26 22:37:59'),(32,32,'恥ずかしくて両手で顔を隠した。','はずかしくてりょうてでかおをかくした。','Hazukashikute ryoute de kao o kakushita.','Dùng hai tay che đi vì xấu hổ.','2025-08-27 00:13:01','2025-08-27 00:13:01'),(33,33,'気づかないうちにコーヒーがこぼれていた。','きづかないうちにこーひーがこぼれていた。','Kizukanai uchi ni koohii ga koborete ita.','Lúc để ý thì cà phê đã bị đổ ra mất rồi.','2025-08-27 00:22:55','2025-08-27 00:22:55'),(274,277,'子供がジュースをこぼした。','こどもがじゅーすをこぼした。','Kodomo ga juusu o koboshita.','Trẻ con ngay lập tức làm vãi cốc nước.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(275,278,'机に本を立てて置く。','つくえにほんをたてておく。','Tsukue ni hon o tatete oku.','Đặt quyển sách dựng đứng ở trên bàn.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(276,279,'くつが泥で汚れた。','くつがどろでよごれた。','Kutsu ga doro de yogoreta.','Đôi giày bị bẩn vì dính bùn.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(277,280,'友達に借りた本を汚してしまった。','ともだちにかりたほんをよごしてしまった。','Tomodachi ni karita hon o yogoshite shimatta.','Tôi làm bẩn sách mượn từ bạn.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(278,281,'テレビが壊れて見られない。','てれびがこわれてみられない。','Terebi ga kowarete mirarenai.','Tivi bị hỏng nên không xem được.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(279,282,'彼はよく物を壊す。','かれはよくものをこわす。','Kare wa yoku mono o kowasu.','Anh ấy thường làm hỏng đồ đạc.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(280,283,'ちゃわんが割れた。','ちゃわんがわれた。','Chawan ga wareta.','Cái bát đã bị vỡ.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(281,284,'木の棒で窓ガラスを割る。','きのぼうでまどがらすをわる。','Ki no bou de mado garasu o waru.','Làm vỡ cửa sổ bằng thanh gỗ.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(282,285,'寝ているお父さんを起こす。','ねているおとうさんをおこす。','Nete iru otousan o okosu.','Đánh thức ông bố đang ngủ.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(283,286,'わたしがタクシーを呼びます。','わたしがたくしーをよびます。','Watashi ga takushii o yobimasu.','Tôi sẽ gọi taxi.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(284,287,'「助けてー」と叫ぶ声が聞こえた。','「たすけてー」とさけぶこえがきこえた。','“Tasukete” to sakebu koe ga kikoeta.','Tôi nghe thấy tiếng hét \'Cứu tôi với\'.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(285,288,'タオルが乾いた。','たおるがかわいた。','Taoru ga kawaita.','Khăn đã khô.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(286,289,'私はいつも、髪を乾かしてから寝る。','わたしはいつも、かみをかわかしてからねる。','Watashi wa itsumo, kami o kawakashite kara neru.','Tôi luôn sấy khô tóc rồi mới đi ngủ.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(287,290,'壊れたギターが直った。','こわれたぎたーがなおった。','Kowareta gitaa ga naotta.','Đàn ghita hỏng đã được sửa.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(288,291,'壊れたパソコンを直す。','こわれたぱそこんをなおす。','Kowareta pasokon o naosu.','Sửa máy tính bị hỏng.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(289,292,'なかなか風邪が治らない。','なかなかかぜがなおらない。','Nakanaka kaze ga naoranai.','Bị cảm mãi mà không khỏi.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(290,293,'ゆっくり休んで、病気を治してください。','ゆっくりやすんで、びょうきをなおしてください。','Yukkuri yasunde, byouki o naoshite kudasai.','Hãy nghỉ ngơi thật tốt và chữa khỏi bệnh.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(291,294,'たくさんあった仕事がやっと片付いた。','たくさんあったしごとがやっとかたづいた。','Takusan atta shigoto ga yatto katadzuita.','Cuối cùng thì những công việc còn chất đống cũng đã được giải quyết xong xuôi.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(292,295,'テーブルの上を片付ける。','てーぶるのうえをかたづける。','Teeburu no ue o katadzukeru.','Dọn dẹp trên bàn.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(293,296,'Youtubeは勉強や仕事に役立つ。','ゆーちゅーぶはべんきょうやしごとにやくだつ。','Yuutuubu wa benkyou ya shigoto ni yakudatsu.','Youtube có ích cho học tập và công việc.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(294,297,'今までの経験を、仕事に役立てる。','いままでのけいけんを、しごとにやくだてる。','Ima made no keiken o, shigoto ni yakudateru.','Áp dụng những kinh nghiệm từ trước tới nay vào trong công việc.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(295,298,'山火事で木が燃えてしまった。','やまかじできがもえてしまった。','Yamakaji de ki ga moete shimatta.','Cây bị thiêu rụi do cháy rừng.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(296,299,'いらなくなった紙を燃やす。','いらなくなったかみをもやす。','Iranakunatta kami o moyasu.','Đốt tờ giấy đã không còn cần thiết.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(297,300,'車とバイクがぶつかった。','くるまとばいくがぶつかった。','Kuruma to baiku ga butsukatta.','Ô tô và xe máy đã va vào nhau.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(298,301,'電柱に車をぶつけてしまった。','でんちゅうにくるまをぶつけてしまった。','Denchuu ni kuruma o butsukete shimatta.','Tôi tông ô tô vào cột điện.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(299,302,'毎朝、バイクに乗って会社に来ている。','まいあさ、ばいくにのってかいしゃにきている。','Maiasa, baiku ni notte kaisha ni kite iru.','Hằng sáng đều đi xe máy tới công ty.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(300,303,'彼女をバイクの後ろに乗せる。','かのじょをばいくのうしろにのせる。','Kanojo o baiku no ushiro ni noseru.','Tôi đèo bạn gái phía sau xe máy.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(301,304,'次の駅で降ります。','つぎのえきでおります。','Tsugi no eki de orimasu.','Xuống tàu ở ga tiếp theo.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(302,305,'あのビルの前で降ろしてください。','あのびるのまえでおろしてください。','Ano biru no mae de oroshite kudasai.','Hãy cho tôi xuống ở phía trước tòa nhà kia.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(303,306,'事故にあったが命は助かった。','じこにあったがいのちはたすかった。','Jiko ni atta ga inochi wa tasukatta.','Tuy gặp tai nạn nhưng bằng cách nào đó vẫn giữ được mạng sống.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(304,307,'川で溺れているねこを助けた。','かわでおぼれているねこをたすけた。','Kawa de oborete iru neko o tasuketa.','Tôi đã cứu một chú mèo suýt chết đuối dưới sông.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(305,308,'私は、日本語を話すことができる。','わたしは、にほんごをはなすことができる。','Watashi wa, nihongo o hanasu koto ga dekiru.','Tôi có thể nói được tiếng Nhật.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(306,309,'ケータイの充電が切れた。','けーたいのじゅうでんがきれた。','Keetai no juuden ga kireta.','Điện thoại hết pin.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(307,310,'しょうゆを切らした。','しょうゆをきらした。','Shouyu o kirashita.','Dùng hết nước tương.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(308,311,'ニュースがすぐに皆に伝わった。','にゅーすがすぐにみんなにつたわった。','Nyuusu ga sugu ni minna ni tsutawatta.','Tin tức được lan truyền trong chớp mắt.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(309,312,'メールで用件を伝える。','めーるでようけんをつたえる。','Meeru de youken o tsutaeru.','Dùng email để truyền đạt yêu cầu.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(310,313,'子供を連れて散歩に行く。','こどもをつれてさんぽにいく。','Kodomo o tsurete sanpo ni iku.','Dẫn con đi dạo.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(311,314,'目覚まし時計が鳴った。','めざましどけいがなった。','Mezamashi tokei ga natta.','Đồng hồ báo thức reo lên.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(312,315,'車のクラクションを鳴らす。','くるまのくらくしょんをならす。','Kuruma no kurakushon o narasu.','Bấm còi ô tô.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(313,316,'電話が動かなくなった。','でんわがうごかなくなった。','Denwa ga ugokanaku natta.','Điện thoại không hoạt động.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(314,317,'定員の人を動かすことができる。','ていいんのひとをうごかすことができる。','Teiin no hito o ugokasu koto ga dekiru.','Làm con búp bê chuyển động.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(315,318,'危ないですから、黄色い線から離れてください。','あぶないですから、きいろいせんからはなれてください。','Abunai desu kara, kiiroi sen kara hanarete kudasai.','Vì nguy hiểm nên hãy tránh xa vạch màu vàng.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(316,319,'机と机の間をもう少し離してください。','つくえとつくえのあいだをもうすこしはなしてください。','Tsukue to tsukue no aida o mou sukoshi hanashite kudasai.','Hãy tách cái bàn ra một chút.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(317,320,'ズボンのポケットに穴が空いてしまった。','ずぼんのぽけっとにあながあいてしまった。','Zubon no poketto ni ana ga aite shimatta.','Ở chỗ đựng quần bị thủng.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(318,321,'紙に穴を空ける。','かみにあなをあける。','Kami ni ana o akeru.','Dục lỗ ở trên giấy.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(319,322,'やっと熱が下がった。','やっとねつがさがった。','Yatto netsu ga sagatta.','Cuối cùng cũng đã hạ sốt.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(320,323,'うるさいから、音量を下げてください。','うるさいから、おんりょうをさげてください。','Urusai kara, onryou o sagete kudasai.','Hãy giảm âm lượng xuống vì ồn quá.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(321,324,'自転車で転んで、ひざをけがした。','じてんしゃでころんで、ひざをけがした。','Jitensha de koronde, hiza o kegashita.','Bị ngã xe đạp nên đầu gối bị trầy xước.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(322,325,'リンゴの皮をむいて食べる。','りんごのかわをむいてたべる。','Ringo no kawa o muite taberu.','Gọt vỏ táo ăn.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(323,326,'朝になると、雪が積もっていた。','あさになると、ゆきがつもっていた。','Asa ni naru to, yuki ga tsumotte ita.','Khi trời sáng, tuyết đã chất đống lại.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(324,327,'トラックに荷物を積む。','とらっくににもつをつむ。','Torakku ni nimotsu o tsumu.','Chất đồ lên xe tải.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(325,328,'私は北海道で生まれた。','わたしはほっかいどうでうまれた。','Watashi wa Hokkaidou de umareta.','Tôi được sinh ra ở Hokkaido.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(326,329,'姉が元気な子を産んだ。','あねがげんきなこをうんだ。','Ane ga genki na ko o unda.','Chị gái tôi đã sinh một bé gái khỏe mạnh.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(327,330,'庭に雑草が生えた。','にわにざっそうがはえた。','Niwa ni zassou ga haeta.','Cỏ dại mọc trong vườn.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(328,331,'長いひげを生やす。','ながいひげをはやす。','Nagai hige o hayasu.','Nuôi râu dài.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(329,332,'この下に宝が埋まっているはずだ。','このしたにたからがうまっているはずだ。','Kono shita ni takara ga umatte iru hazu da.','Chắc chắn kho báu được chôn ở dưới này.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(330,333,'地面にごみを埋める。','じめんにごみをうめる。','Jimen ni gomi o umeru.','Chôn rác ở dưới mặt đất.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(331,334,'のどが渇いたのでオレンジジュースを飲む。','のどがかわいたのでおれんじじゅーすをのむ。','Nodo ga kawaita node orenji juusu o nomu.','Vì khát nên tôi uống nước cam.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(332,335,'食べもののにおいを嗅いで、何かあやしいと感じる。','たべもののにおいをかいで、なにかあやしいとかんじる。','Tabemono no nioi o kaide, nanika ayashii to kanjiru.','Ngửi mùi đồ ăn thấy có gì đó lạ.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(333,336,'お父さんの肩を叩いた。','おとうさんのかたをたたいた。','Otousan no kata o tataita.','Tôi vỗ vai bố.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(334,337,'サッカーボールを殴る。','さっかーぼーるをなぐる。','Sakkaa booru o naguru.','Đá bóng.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(335,338,'彼は怒ると、人を蹴る。','かれはおこると、ひとをける。','Kare wa okoru to, hito o keru.','Khi tức giận, anh ấy lại đá người khác.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(336,339,'泣いている子供を抱く。','ないているこどもをだく。','Naite iru kodomo o daku.','Ôm đứa bé đang khóc.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(337,340,'タオルで顔を拭く。','たおるでかおをふく。','Taoru de kao o fuku.','Lau mặt bằng khăn.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(338,341,'クッキーをティッシュに包む。','くっきーをてぃっしゅにつつむ。','Kukkii o tisshu ni tsutsumu.','Gói bánh cookie trong giấy ăn.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(339,342,'手紙に切手を貼る。','てがみにきってをはる。','Tegami ni kitte o haru.','Dán tem vào thư.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(340,343,'貯金をすれば、今の収入で十分に足りる。','ちょきんをすれば、いまのしゅうにゅうでじゅうぶんにたりる。','Chokin o sureba, ima no shuunyuu de juubun ni tariru.','Nếu không tiêu xài hoang phí, thì với thu nhập hiện tại là quá đủ.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(341,344,'卵が腐った。','たまごがくさった。','Tamago ga kusatta.','Trứng bị thối.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(342,345,'冬は、スキーを滑ることができるので好きだ。','ふゆは、すきをすべることができるのですきだ。','Fuyu wa, sukii o suberu koto ga dekiru node suki da.','Tôi thích mùa đông vì có thể trượt tuyết.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(343,346,'わたしたちは、大学で出会いました。','わたしたちは、だいがくでであいました。','Watashitachi wa, daigaku de deaimashita.','Chúng tôi đã gặp gỡ nhau ở trường đại học.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(344,347,'先生の自宅を訪ねた。','せんせいのじたくをたずねた。','Sensei no jitaku o tazuneta.','Đến thăm nhà thầy giáo.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(345,348,'村上くんはベトナム人と付き合っているらしい。','むらかみくんはべとなむじんとつきあっているらしい。','Murakami-kun wa Betonamujin to tsukiatte iru rashii.','Nghe nói cậu Murakami đang hẹn hò với người Việt.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(346,349,'この薬は、疲れにとてもよく効く。','このくすりは、つかれにとてもよくきく。','Kono kusuri wa, tsukare ni totemo yoku kiku.','Loại thuốc này rất hiệu quả với việc trị mệt mỏi.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(347,350,'この夏は、紫色のファッションがはやっている。','このなつは、むらさきいろのふぁっしょんがはやっている。','Kono natsu wa, murasaki iro no fasshon ga hayatte iru.','Mùa hè này, thời trang màu tím đang thịnh hành.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(348,351,'大学卒業から5年が経った。','だいがくそつぎょうから5ねんがたった。','Daigaku sotsugyou kara go-nen ga tatta.','Đã 5 năm kể từ ngày tốt nghiệp Đại học.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(349,352,'歩いているおばあさんに道を尋ねた。','あるいているおばあさんにみちをたずねた。','Aruite iru obaasan ni michi o tazuneta.','Tôi hỏi đường một bà cụ đang đi bộ.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(350,353,'質問をしても彼は黙ったままだ。','しつもんをしてもかれはだまったままだ。','Shitsumon o shitemo kare wa damatta mama da.','Dù có hỏi thì anh ấy vẫn im lặng.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(351,354,'洋服を畳む。','ようふくをたたむ。','Youfuku o tatamu.','Gấp (xếp) quần áo.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(352,355,'彼氏を誘ってピザを食べに行った。','かれしをさそってぴざをたべにいった。','Kareshi o sasotte piza o tabe ni itta.','Tôi đã mời bạn trai đi ăn pizza.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(353,356,'ひいおばあさんは93歳で亡くなった。','ひいおばあさんは93さいでなくなった。','Hii obaasan wa 93-sai de nakunatta.','Cụ (bà) tôi mất năm 93 tuổi.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(354,357,'戦争で夫を亡くした。','せんそうでおっとをなくした。','Sensou de otto o nakushita.','Chồng mất do chiến tranh.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(355,358,'スピード違反で捕まった。','すぴーどいはんでつかまった。','Supiido ihan de tsukamatta.','Bị bắt do chạy quá tốc độ.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(356,359,'どろぼうを捕まえる。','どろぼうをつかまえる。','Dorobou o tsukamaeru.','Bắt kẻ trộm.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(357,360,'なくしていた財布がカバンの中から見つかった。','なくしていたさいふがかばんのなかからみつかった。','Nakushite ita saifu ga kaban no naka kara mitsukatta.','Chiếc ví bị mất đã được tìm thấy trong cặp.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(358,361,'新しい仕事を見つける。','あたらしいしごとをみつける。','Atarashii shigoto o mitsukeru.','Tìm thấy công việc mới.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(359,362,'友達が手作り料理をごちそうしてくれた。','ともだちがてづくりりょうりをごちそうしてくれた。','Tomodachi ga tezukuri ryouri o gochisou shite kureta.','Bạn tôi đãi tôi bằng đồ ăn tự làm.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(360,363,'先輩がラーメンをおごってくれた。','せんぱいがらーめんをおごってくれた。','Senpai ga raamen o ogotte kureta.','Senpai đã khao tôi mì ramen.','2025-08-27 00:26:34','2025-08-27 00:26:34'),(361,364,'友達の子供を預かる。','ともだちのこどもをあずかる。','Tomodachi no kodomo o azukaru.','Tôi trông con hộ bạn.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(362,365,'銀行にお金を預ける。','ぎんこうにおかねをあずける。','Ginkou ni okane o azukeru.','Tôi gửi tiền trong ngân hàng.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(363,366,'旅行の行き先は沖縄に決まった。','りょこうのいきさきはおきなわにきまった。','Ryokou no ikisaki wa Okinawa ni kimatta.','Điểm đến của chuyến đi đã được quyết định là Okinawa.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(364,367,'売り時間１分でゴールを決めた。','うりじかんいっぷんでごーるをきめた。','Uri jikan ippun de gooru o kimeta.','Tôi đã ghi bàn khi thời gian chỉ còn một phút.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(365,368,'この旅行の写真に友達が写っていた。','このりょこうのしゃしんにともだちがうつっていた。','Kono ryokou no shashin ni tomodachi ga utsutte ita.','Có dính cả người không quen biết trong ảnh chuyến du lịch.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(366,369,'パーティーの様子を写す。','ぱーてぃーのようすをうつす。','Paatii no yousu o utsusu.','Chụp lại khung cảnh bữa tiệc.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(367,370,'あの人の名前が思い出せない。','あのひとのなまえがおもいだせない。','Ano hito no namae ga omoidasenai.','Tôi không thể nhớ ra tên của người đó.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(368,371,'先生から日本語を教わりました。','せんせいからにほんごをおそわりました。','Sensei kara nihongo o osowarimashita.','Tôi đã được cô giáo dạy cho tiếng Nhật.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(369,372,'デートの誘いを断った。','でーとのさそいをことわった。','Deeto no sasoi o kotowatta.','Tôi đã từ chối lời mời hẹn hò.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(370,373,'寝坊をしたが、なんとか授業に間に合った。','ねぼうをしたが、なんとかじゅぎょうにまにあった。','Nebou o shitaga, nantoka jugyou ni maniatta.','Tôi ngủ quên nhưng may vẫn kịp giờ học.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(371,374,'宿題をして、締め切りまでに間に合わせた。','しゅくだいをして、しめきりまでにまにあわせた。','Shukudai o shite, shimekiri made ni maniawaseta.','Tôi đã làm xong bài tập để kịp hạn chót.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(372,375,'毎週ギターのレッスンに通っている。','まいしゅうぎたーのれっすんにかよっている。','Maishuu gitaa no ressun ni kayotte iru.','Tôi đi học lớp guitar hằng tuần.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(373,376,'朝の時間の電車は込む。','あさのじかんのでんしゃはこむ。','Asa no jikan no densha wa komu.','Các chuyến tàu sáng thường đông đúc.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(374,377,'スーパーで先生とすれ違った。','すーぱーでせんせいとすれちがった。','Suupaa de sensei to surechigatta.','Tôi đã lướt qua cô giáo trong siêu thị.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(375,378,'経費が掛かる。','けいひがかかる。','Keihi ga kakaru.','Tốn kinh phí.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(376,379,'彼に布団を掛ける。','かれにふとんをかける。','Kare ni futon o kakeru.','Đắp chăn cho bạn trai đang ngủ.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(377,380,'世界の人口が増える。','せかいのじんこうがふえる。','Sekai no jinkou ga fueru.','Dân số thế giới tăng lên.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(378,381,'貯金を増やす。','ちょきんをふやす。','Chokin o fuyasu.','Tăng tiền tiết kiệm thêm.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(379,382,'無駄な時間を減らす。','むだなじかんをへらす。','Mudana jikan o herasu.','Giảm thời gian lãng phí.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(380,383,'前より家族と話す機会が減った。','まえよりかぞくとはなすきかいがへった。','Mae yori kazoku to hanasu kikai ga hetta.','Tôi có ít cơ hội để trò chuyện với gia đình hơn so với hồi trước.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(381,384,'自分と他人を比べる。','じぶんとたにんをくらべる。','Jibun to tanin o kuraberu.','So sánh bản thân với người khác.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(382,385,'彼女は赤がよく似合う。','かのじょはあかがよくにあう。','Kanojo wa aka ga yoku niau.','Cô ấy hợp với màu đỏ.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(383,386,'彼らは性格がよく似ている。','かれらはせいかくがよくにている。','Karera wa seikaku ga yoku nite iru.','Chúng nó rất giống nhau về tính cách.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(384,387,'有名な俳優の髪型を似せる。','ゆうめいなはいゆうのかみがたをにせる。','Yuumei na haiyuu no kamigata o niseru.','Tôi bắt chước kiểu tóc của diễn viên nổi tiếng.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(385,388,'意見が分かれる。','いけんがわかれる。','Iken ga wakareru.','Các ý kiến tại cuộc họp bị chia ra.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(386,389,'母からもらったお菓子を兄弟で分ける。','ははからもらったおかしをきょうだいでわける。','Haha kara moratta okashi o kyoudai de wakeru.','Anh em tôi chia nhau kẹo mẹ cho.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(387,390,'牛乳に砂糖を足して、少し甘くする。','ぎゅうにゅうにさとうをたして、すこしあまくする。','Gyuunyuu ni satou o tashite, sukoshi amaku suru.','Thêm đường vào sữa cho ngọt thêm một chút.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(388,391,'重要な言葉に線を引く。','じゅうようなことばにせんをひく。','Juuyou na kotoba ni sen o hiku.','Gạch chân những từ quan trọng.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(389,392,'この地域は山に囲まれている。','このちいきはやまにかこまれている。','Kono chiiki wa yama ni kakomarete iru.','Khu vực này được bao quanh bởi nhiều ngọn núi.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(390,393,'部屋に人を詰めて入れる。','へやにひとをつめていれる。','Heya ni hito o tsumete ireru.','Nhồi nhét người vào trong phòng.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(391,394,'本棚に本がぎっしり詰まっている。','ほんだなにほんがぎっしりつまっている。','Hondana ni hon ga gisshiri tsumatte iru.','Trên giá được chất đầy sách.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(392,395,'やっとベトナムの生活に慣れた。','やっとべとなむのせいかつになれた。','Yatto Betonamu no seikatsu ni nareta.','Cuối cùng thì tôi cũng quen với cuộc sống ở Việt Nam.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(393,396,'運動で体を慣らしてから泳ぐ。','うんどうでからだをならしてからおよぐ。','Undou de karada o narashite kara oyogu.','Khởi động cơ thể cho quen rồi mới bơi.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(394,397,'彼女の髪型が変わった。','かのじょのかみがたがかわった。','Kanojo no kamigata ga kawatta.','Kiểu tóc của cô ấy đã thay đổi.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(395,398,'彼との出会いが私の人生を変えた。','かれとのであいがわたしのじんせいをかえた。','Kare to no deai ga watashi no jinsei o kaeta.','Gặp được anh ấy đã thay đổi cuộc sống của tôi.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(396,399,'先生が新しい人に代わった。','せんせいがあたらしいひとにかわった。','Sensei ga atarashii hito ni kawatta.','Thầy giáo được thay bằng người mới.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(397,400,'古い靴を新しいものと替える。','ふるいくつをあたらしいものとかえる。','Furui kutsu o atarashii mono to kaeru.','Thay một cái giày mới.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(398,401,'友達に貸したマンガが返ってきた。','ともだちにかしたまんががかえってきた。','Tomodachi ni kashita manga ga kaette kita.','Cuốn truyện tôi cho bạn mượn đã được trả lại.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(399,402,'借りたお金は必ず返す。','かりたおかねはかならずかえす。','Karita okane wa kanarazu kaesu.','Tiền đã mượn nhất định phải trả.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(400,403,'N5の問題を間違えた。','えぬごのもんだいをまちがえた。','Enugo no mondai o machigaeta.','Đã làm sai bài tập N5.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(401,404,'彼の名前を間違えた。','かれのなまえをまちがえた。','Kare no namae o machigaeta.','Tôi nhầm sang tên người khác.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(402,405,'このジュースはビタミンを多く含んでいる。','このじゅーすはびたみんをおおくふくんでいる。','Kono juusu wa bitamin o ooku fukunde iru.','Nước ép này chứa nhiều vitamin.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(403,406,'消費税を含めて合計150円です。','しょうひぜいをふくめてごうけい150えんです。','Shouhizei o fukumete goukei hyaku gojuu en desu.','Tổng cộng là 150 yên bao gồm cả thuế tiêu thụ.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(404,407,'クラスのメンバーが一人抜けた。','くらすのめんばーがひとりぬけた。','Kurasu no menbaa ga hitori nuketa.','Lớp có một người bị bỏ lại.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(405,408,'ワインの栓を抜く。','わいんのせんをぬく。','Wain no sen o nuku.','Mở nắp chai rượu vang.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(406,409,'雲が晴れて、月が現れた。','くもがはれて、つきがあらわれた。','Kumo ga harete, tsuki ga arawareta.','Mây tan và trăng bỗng xuất hiện.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(407,410,'夜になると、夜行性のライオンが姿を現す。','よるになると、やこうせいのらいおんがすがたをあらわす。','Yoru ni naru to, yakousei no raion ga sugata o arawasu.','Vào buổi tối, con sư tử hoạt động về đêm xuất hiện.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(408,411,'嘘をついたことが顔に表れた。','うそをついたことがかおにあらわれた。','Uso o tsuita koto ga kao ni arawareta.','Gương mặt thể hiện rõ rằng anh ta đã nói dối.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(409,412,'彼女への気持ちを歌で表す。','かのじょへのきもちをうたであらわす。','Kanojo e no kimochi o uta de arawasu.','Thể hiện tình cảm với bạn gái bằng bài hát.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(410,413,'桜が散る景色は美しい。','さくらがちるけしきはうつくしい。','Sakura ga chiru keshiki wa utsukushii.','Khung cảnh hoa anh đào rơi thật đẹp.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(411,414,'料理の上にパセリを散らす。','りょうりのうえにぱせりをちらす。','Ryouri no ue ni paseri o chirasu.','Rắc rau mùi tây lên món ăn vừa hoàn thành.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(412,415,'これからも、人生は続く。','これからも、じんせいはつづく。','Kore kara mo, jinsei wa tsuzuku.','Từ bây giờ, cuộc sống vẫn sẽ tiếp tục.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(413,416,'ピアノを続けるのは難しい。','ぴあのをつづけるのはむずかしい。','Piano o tsuzukeru no wa muzukashii.','Tiếp tục chơi piano là điều khó khăn.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(414,417,'髪が伸びる。','かみがのびる。','Kami ga nobiru.','Tóc dài ra.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(415,418,'髪を伸ばす。','かみをのばす。','Kami o nobasu.','Tôi nuôi tóc dài.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(416,419,'レポートの締め切りが延びる。','れぽーとのしめきりがのびる。','Repōto no shimekiri ga nobiru.','Thời hạn báo cáo được gia hạn.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(417,420,'テストの時間を１０分延ばす。','てすとのじかんを１０ぷんのばす。','Tesuto no jikan o juppun nobasu.','Kéo dài thời gian làm bài kiểm tra thêm 10 phút.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(418,421,'予定と会議の時間が重なった。','よていとかいぎのじかんがかさなった。','Yotei to kaigi no jikan ga kasanatta.','Lịch làm việc và cuộc họp bị trùng nhau.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(419,422,'Ｔシャツを２枚重ねて着る。','Ｔしゃつを２まいかさねてきる。','T-shatsu o nimai kasanete kiru.','Mặc 2 chiếc áo phông lồng vào nhau.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(420,423,'お金が貯まったので、海外旅行に行く。','おかねがたまったので、かいがいりょこうにいく。','Okane ga tamatta node, kaigai ryokou ni iku.','Tiền đã tiết kiệm đủ, đi du lịch nước ngoài nào.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(421,424,'バケツの中に水を貯める。','ばけつのなかにみずをためる。','Baketsu no naka ni mizu o tameru.','Dùng nước để tích trong xô.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(422,425,'新聞に自分が撮った写真が載る。','しんぶんにじぶんがとったしゃしんがのる。','Shinbun ni jibun ga totta shashin ga noru.','Bức ảnh tôi chụp được đăng lên báo.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(423,426,'車に荷物を載せる。','くるまににもつをのせる。','Kuruma ni nimotsu o noseru.','Chất hành lý lên xe.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(424,427,'全員そろってミーティングを始める。','ぜんいんそろってみーてぃんぐをはじめる。','Zen’in sorotte miitingu o hajimeru.','Mọi người tập trung đầy đủ bắt đầu họp.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(425,428,'パーティーのための食材をそろえる。','ぱーてぃーのためのしょくざいをそろえる。','Paatii no tame no shokuzai o soroeru.','Chuẩn bị nguyên liệu cho bữa tiệc.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(426,429,'足に釘が刺さった。','あしにくぎがささった。','Ashi ni kugi ga sasatta.','Đã bị kim đâm vào chân.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(427,430,'後ろから包丁で背中を刺された。','うしろからほうちょうでせなかをさされた。','Ushiro kara houchou de senaka o sasareta.','Bị dao đâm vào lưng từ phía sau.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(428,431,'犯人は１０人も殺した。','はんにんは１０にんもころした。','Hannin wa juunin mo koroshita.','Tên tội phạm đã giết tận 10 người.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(429,432,'台風が近づいている。','たいふうがちかづいている。','Taifuu ga chikadzuite iru.','Cơn bão đang đến gần.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(430,433,'最近目が悪く、顔を近づけないと字が読めない。','さいきんめがわるく、かおをちかづけないとじがよめない。','Saikin me ga waruku, kao o chikadzukenai to ji ga yomenai.','Dạo này mắt tôi kém, nếu không đưa lại gần mặt thì không thể đọc nổi chữ.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(431,434,'なぜか田中さんとよく目が合う。','なぜかたなかさんとよくめがあう。','Naze ka Tanaka-san to yoku me ga au.','Không hiểu sao gần đây tôi hay bắt gặp ánh mắt của Tanaka.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(432,435,'場所に合わせて服装を変える。','ばしょにあわせてふくそうをかえる。','Basho ni awasete fukusou o kaeru.','Thay đổi trang phục để phù hợp với địa điểm.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(433,436,'宝くじに一万円が当たった。','たからくじにいちまんえんがあたった。','Takarakuji ni ichiman en ga atatta.','Tôi đã trúng xổ số 1 vạn yên.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(434,437,'的にボールを当てる。','まとにぼーるをあてる。','Mato ni booru o ateru.','Đánh bóng trúng tâm.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(435,438,'なかなか話がまとまらない。','なかなかはなしがまとまらない。','Nakanaka hanashi ga matomaranai.','Cuộc thảo luận mãi mà vẫn chưa đi tới thống nhất.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(436,439,'考えをまとめて発表する。','かんがえをまとめてはっぴょうする。','Kangae o matomete happyou suru.','Tổng kết lại ý kiến rồi phát biểu.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(437,440,'服にソースがついてしまった。','ふくにそーすがついてしまった。','Fuku ni soosu ga tsuite shimatta.','Nước sốt bị dính vào quần áo.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(438,441,'出かける前に香水をつける。','でかけるまえにこうすいをつける。','Dekakeru mae ni kousui o tsukeru.','Xịt nước hoa trước khi ra ngoài.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(439,442,'男の子の中に女の子が交じって遊んでいる。','おとこのこのなかにおんなのこがまじってあそんでいる。','Otoko no ko no naka ni onna no ko ga majitte asonde iru.','Lẫn trong nhóm các bé trai có các bé gái đang chơi đùa.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(440,443,'材料がよく交ざっていなかったため、失敗した。','ざいりょうがよくまざっていなかったため、しっぱいした。','Zairyou ga yoku mazatte inakatta tame, shippai shita.','Tôi đã không làm ra được một chiếc bánh ngon vì các nguyên liệu không được trộn đều.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(441,444,'ご飯に玄米を交ぜる。','ごはんにげんまいをまぜる。','Gohan ni genmai o mazeru.','Trộn gạo lứt vào cơm trắng.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(442,445,'この問題が解けなくて、困ります。','このもんだいがとけなくて、こまります。','Kono mondai ga tokenakute, komarimasu.','Tôi không thể về cho đến khi vấn đề này được giải quyết.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(443,446,'試験の問題を解く。','しけんのもんだいをとく。','Shiken no mondai o toku.','Giải bài tập khoa học.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(444,447,'友達に私の好きな映画を勧める。','ともだちにわたしのすきなえいがをすすめる。','Tomodachi ni watashi no sukina eiga o susumeru.','Tôi giới thiệu cho bạn bộ phim tôi yêu thích.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(445,448,'海外にいる友達から荷物が届いた。','かいがいにいるともだちからにもつがとどいた。','Kaigai ni iru tomodachi kara nimotsu ga todoita.','Gói hàng từ người bạn nước ngoài đã được gửi đến.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(446,449,'友達がお土産を届けに来てくれた。','ともだちがおみやげをとどけにきてくれた。','Tomodachi ga omiyage o todoke ni kite kureta.','Một người bạn đến để đưa quà lưu niệm cho tôi.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(447,450,'前を向いて歩く。','まえをむいてあるく。','Mae o muite aruku.','Luôn hướng về phía trước.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(448,451,'顔を左に向けてください。','かおをひだりにむけてください。','Kao o hidari ni mukete kudasai.','Hãy quay mặt sang bên trái.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(449,452,'国語試験に合格して大学に通った。','こくごしけんにごうかくしてだいがくにとおった。','Kokugo shiken ni goukaku shite daigaku ni tootta.','Tôi đã vượt qua kì thi tuyển công chức quốc gia.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(450,453,'会議でこの企画を通したい。','かいぎでこのきかくをとおしたい。','Kaigi de kono kikaku o tooshitai.','Tôi muốn thông qua dự án này tại cuộc họp.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(451,454,'先月、新しいマンションに移った。','せんげつ、あたらしいまんしょんにうつった。','Sengetsu, atarashii manshon ni utsutta.','Tôi đã chuyển đến khu chung cư mới vào tháng trước.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(452,455,'金を新しい財布へ移す。','かねをあたらしいさいふへうつす。','Kane o atarashii saifu e utsusu.','Chuyển tiền sang ví mới.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(453,456,'波が大きく揺れている。','なみがおおきくゆれている。','Nami ga ookiku yurete iru.','Những con sóng lớn đang nhấp nhô.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(454,457,'木を揺らしてリンゴを落とす。','きをゆらしてりんごをおとす。','Ki o yurashite ringo o otosu.','Rung cây làm táo rơi xuống.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(455,458,'川に水が流れている。','かわにみずがながれている。','Kawa ni mizu ga nagarete iru.','Nước đang chảy trên sông.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(456,459,'川にごみを流す。','かわにごみをながす。','Kawa ni gomi o nagasu.','Xả rác thải ra sông.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(457,460,'山に上る。','やまにのぼる。','Yama ni noboru.','Leo núi.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(458,461,'自転車で坂を下る。','じてんしゃでさかをくだる。','Jitensha de saka o kudaru.','Đi xe đạp xuống dốc.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(459,462,'手伝通りに作業が進んでいる。','てつだいどおりにさぎょうがすすんでいる。','Tetsudai doori ni sagyou ga susunde iru.','Công việc tiến triển theo như dự định.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(460,463,'バイクを前に進める。','ばいくをまえにすすめる。','Baiku o mae ni susumeru.','Tiến xe máy lên phía trước.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(461,464,'母の声で目を覚ます。','ははのこえでめをさます。','Haha no koe de me o samasu.','Tỉnh giấc bởi giọng của mẹ.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(462,465,'今、誰かが家の前を通り過ぎました。','いま、だれかがいえのまえをとおりすぎました。','Ima, dareka ga ie no mae o toorisugimashita.','Có cảm giác ai đó đi ngang qua trước cửa nhà tôi lúc này.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(463,466,'休日は家族と一緒に過ごしたい。','きゅうじつはかぞくといっしょにすごしたい。','Kyuujitsu wa kazoku to issho ni sugoshitai.','Tôi muốn tận hưởng ngày nghỉ cùng gia đình.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(464,467,'いい考えが思いついた。','いいかんがえがおもいついた。','Ii kangae ga omoitsuita.','Tôi đã nghĩ ra một ý tưởng hay.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(465,468,'彼は思いやりにあふれた人です。','かれはおもいやりにあふれたひとです。','Kare wa omoiyari ni afureta hito desu.','Anh ấy là người luôn quan tâm tới người khác.','2025-08-27 00:26:49','2025-08-27 00:26:49'),(466,469,'留学のための手続きはすべて済んだ。','りゅうがくのためのてつづきはすべてすんだ。','Ryuugaku no tame no tetsuzuki wa subete sunda.','Các thủ tục để du học đã được hoàn tất.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(467,470,'今日の仕事を時間内に済ませる。','きょうのしごとをじかんないにすませる。','Kyou no shigoto o jikan nai ni sumaseru.','Hoàn thành công việc ngày hôm nay trong thời gian đã định.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(468,471,'彼氏のそばに寄る。','かれしのそばによる。','Kareshi no soba ni yoru.','Sát lại bên cạnh bạn trai.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(469,472,'彼に思いを寄せる。','かれにおもいをよせる。','Kare ni omoi o yoseru.','Có cảm tình với anh ấy.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(470,473,'クラスの雰囲気に影響を与える。','くらすのふんいきにえいきょうをあたえる。','Kurasu no fun\'iki ni eikyou o ataeru.','Gây ảnh hưởng tới bầu không khí trong lớp.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(471,474,'お客様からの信頼を得る。','おきゃくさまからのしんらいをえる。','Okyakusama kara no shinrai o eru.','Có được sự tin nhiệm từ khách hàng.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(472,475,'雨で服が濡れた。','あめでふくがぬれた。','Ame de fuku ga nureta.','Quần áo bị ướt vì trời mưa.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(473,476,'かばんを濡らしてしまった。','かばんをぬらしてしまった。','Kaban o nurashite shimatta.','Tôi làm ướt cặp.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(474,477,'友達に電話がつながらなかった。','ともだちにでんわがつながらなかった。','Tomodachi ni denwa ga tsunagaranakatta.','Không thể liên hệ điện thoại với bạn.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(475,478,'彼女と手をつなぐ。','かのじょとてをつなぐ。','Kanojo to te o tsunagu.','Nắm tay bạn gái.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(476,479,'ピンチをチャンスにつなげる。','ぴんちをちゃんすにつなげる。','Pinchi o chansu ni tsunageru.','Biến nguy cơ thành cơ hội.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(477,480,'娘が遊びに行くのを許した。','むすめがあそびにいくのをゆるした。','Musume ga asobi ni iku no o yurushita.','Cho phép con gái đi chơi.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(478,481,'新しい技術が広まる。','あたらしいぎじゅつがひろまる。','Atarashii gijutsu ga hiromaru.','Công nghệ mới trở nên phổ biến rộng rãi.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(479,482,'彼はYouTubeで自分の考えを広めた。','かれはゆーちゅーぶでじぶんのかんがえをひろめた。','Kare wa Yuuchuubu de jibun no kangae o hirometa.','Anh ta đã lan tỏa tư tưởng của bản thân đến toàn Nhật Bản bằng Youtube.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(480,483,'工事をして、道路が広がった。','こうじをして、どうろがひろがった。','Kouji o shite, douro ga hirogatta.','Con đường được mở rộng sau khi thi công.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(481,484,'新聞を広げて読む。','しんぶんをひろげてよむ。','Shinbun o hirogete yomu.','Mở rộng tờ báo ra đọc.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(482,485,'台風の勢力が弱まる。','たいふうのせいりょくがよわまる。','Taifuu no seiryoku ga yowamaru.','Sức mạnh của cơn bão đã suy yếu đi.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(483,486,'火を弱めて煮る。','ひをよわめてにる。','Hi o yowamete niru.','Hạ nhỏ lửa và nấu.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(484,487,'台風で雨風が強まった。','たいふうであめかぜがつよまった。','Taifuu de amekaze ga tsuyomatta.','Vì bão nên mưa gió mạnh hơn.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(485,488,'コンロの火を強める。','こんろのひをつよめる。','Konro no hi o tsuyomeru.','Tăng lửa trên bếp gas.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(486,489,'試合前に気持ちが高まる。','しあいまえにきもちがたかまる。','Shiai mae ni kimochi ga takamaru.','Nâng cao tinh thần trước trận đấu.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(487,490,'運動をして体力を高める。','うんどうをしてたいりょくをたかめる。','Undou o shite tairyoku o takameru.','Tập thể dục để nâng cao thể chất.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(488,491,'友達との友情が深まる。','ともだちとのゆうじょうがふかまる。','Tomodachi to no yuujou ga fukamaru.','Mối quan hệ bạn bè trở nên sâu sắc hơn.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(489,492,'理解を深める。','りかいをふかめる。','Rikai o fukameru.','Thắt chặt mối quan hệ tin tưởng.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(490,493,'運動をすると体が温まる。','うんどうをするとからだがあたたまる。','Undou o suru to karada ga atatamaru.','Hễ vận động cơ thể sẽ ấm lên.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(491,494,'ストーブで部屋を温める。','すとーぶでへやをあたためる。','Sutoobu de heya o atatameru.','Bật lò sưởi làm ấm phòng.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(492,495,'日に焼けて、肌の色が変わった。','ひにやけて、はだのいろがかわった。','Hi ni yakete, hada no iro ga kawatta.','Bị rám nắng nên màu da thay đổi.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(493,496,'フライパンでベーコンを焼く。','ふらいぱんでべーこんをやく。','Furaipan de beekon o yaku.','Rang thịt xông khói bằng chảo.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(494,497,'ご飯が炊けたので、夕食の準備をする。','ごはんがたけたので、ゆうしょくのじゅんびをする。','Gohan ga taketa node, yuushoku no junbi o suru.','Cơm đã chín nên giờ chuẩn bị ăn tối.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(495,498,'朝ごはん用に、ご飯を炊く。','あさごはんように、ごはんをたく。','Asagohan you ni, gohan o taku.','Nấu cơm chuẩn bị bữa sáng.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(496,499,'じゃがいもが煮える。','じゃがいもがにえる。','Jagaimo ga nieru.','Khoai tây được ninh nhừ.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(497,500,'やさいを煮て、味を付ける。','やさいをにて、あじをつける。','Yasai o nite, aji o tsukeru.','Ninh rau rồi nêm gia vị.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(498,501,'肉と野菜を炒める。','にくとやさいをいためる。','Niku to yasai o itameru.','Xào rau với thịt.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(499,502,'卵と野菜をゆでる。','たまとやさいをゆでる。','Tamago to yasai o yuderu.','Luộc trứng và rau củ.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(500,503,'やさいを揚げて、天ぷらを作る。','やさいをあげて、てんぷらをつくる。','Yasai o agete, tenpura o tsukuru.','Chiên rau làm tempura.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(501,504,'お湯をわかして、肉まんを蒸す。','おゆをわかして、にくまんをむす。','Oyu o wakashite, nikuman o musu.','Đun nước sôi để hấp bánh bao.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(502,505,'爪でかゆい所を掻く。','つめでかゆいところをかく。','Tsume de kayui tokoro o kaku.','Dùng móng tay gãi chỗ ngứa.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(503,506,'彼は俳優になるチャンスをつかんだ。','かれははいゆうになるちゃんすをつかんだ。','Kare wa haiyuu ni naru chansu o tsukanda.','Anh ta đã nắm lấy cơ hội để trở thành diễn viên.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(504,507,'ペンを握って文字を書く。','ぺんをにぎってもじをかく。','Pen o nigitte moji o kaku.','Cầm bút viết chữ cái.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(505,508,'ドアを手で押さえる。','どあをてでおさえる。','Doa o te de osaeru.','Dùng tay giữ cánh cửa không bị đóng lại.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(506,509,'弱い者をいじめる。','よわいものをいじめる。','Yowai mono o ijimeru.','Bắt nạt kẻ yếu.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(507,510,'年寄りをだまして金を取る。','としよりをだましてかねをとる。','Toshiyori o damashite kane o toru.','Lừa người già để lấy tiền.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(508,511,'知らない人に手を振られた。','しらないひとにてをふられた。','Shiranai hito ni te o furareta.','Người không quen biết vẫy tay gọi tôi.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(509,512,'本を1ページめくる。','ほんを1ぺーじめくる。','Hon o ichi peeji mekuru.','Lật 1 trang sách.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(510,513,'駅で山田さんを見かけた。','えきでやまださんをみかけた。','Eki de Yamada san o mikaketa.','Bắt gặp anh Yamada trong nhà ga.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(511,514,'電話番号を確かめる。','でんわばんごうをたしかめる。','Denwa bangou o tashikameru.','Xác minh số điện thoại.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(512,515,'このバイクが動くかどうか試してみる。','このばいくがうごくかどうかためしてみる。','Kono baiku ga ugoku ka dou ka tameshite miru.','Thử xem chiếc xe máy có chạy hay không.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(513,516,'最近同じ失敗を繰り返している。','さいきんおなじしっぱいをくりかえしている。','Saikin onaji shippai o kurikaeshite iru.','Gần đây tôi cứ lặp lại những công việc giống nhau mỗi ngày.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(514,517,'彼女の言葉を訳す。','かのじょのことばをやくす。','Kanojo no kotoba o yakusu.','Dịch những lời nói của cô ấy.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(515,518,'明日ここで試験が行われる。','あすここでしけんがおこなわれる。','Asu koko de shiken ga okonawareru.','Kỳ thi sẽ được tổ chức tại đây vào ngày mai.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(516,519,'学生の時はスポーツに熱中していた。','がくせいのときはすぽーつにねっちゅうしていた。','Gakusei no toki wa supootsu ni necchuu shite ita.','Hồi học sinh tôi rất đam mê thể thao.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(517,520,'家族と一緒に暮らしている。','かぞくといっしょにくらしている。','Kazoku to issho ni kurashite iru.','Tôi sống cùng gia đình.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(518,521,'マフラーを首に巻く。','まふらーをくびにまく。','Mafuraa o kubi ni maku.','Quàng khăn quanh cổ.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(519,522,'靴のひもを結ぶ。','くつのひもをむすぶ。','Kutsu no himo o musubu.','Buộc dây giày.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(520,523,'あとは山田さんに任せておく。','あとはやまださんにまかせておく。','Ato wa Yamada-san ni makasete oku.','Còn lại thì giao việc cho Yamada.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(521,524,'太陽の光から肌を守る。','たいようのひかりからはだをまもる。','Taiyou no hikari kara hada o mamoru.','Bảo vệ da khỏi ánh sáng mặt trời.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(522,525,'くだらない事で争うな。','くだらないことであらそうな。','Kudaranai koto de arasou na.','Đừng tranh giành vì những điều nhỏ nhặt.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(523,526,'私の望みは、家族が健康でいることだ。','わたしののぞみは、かぞくがけんこうでいることだ。','Watashi no nozomi wa, kazoku ga kenkou de iru koto da.','Điều tôi mong muốn là gia đình được khỏe mạnh.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(524,527,'彼の言葉を信じる。','かれのことばをしんじる。','Kare no kotoba o shinjiru.','Tôi tin vào câu chuyện của anh ấy.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(525,528,'トンネルは海まで通じている。','とんねるはうみまでつうじている。','Tonneru wa umi made tsuujite iru.','Đường hầm này dẫn ra biển.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(526,529,'このゲームにはもう飽きた。','このげーむにはもうあきた。','Kono geemu ni wa mou akita.','Tôi đã mệt mỏi với trò chơi này.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(527,530,'バスでおじいさんに席を譲った。','ばすでおじいさんにせきをゆずった。','Basu de ojiisan ni seki o yuzutta.','Tôi nhường ghế cho ông cụ trên xe buýt.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(528,531,'来場者が100万人を越えた。','らいじょうしゃが100まんにんをこえた。','Raijousha ga hyakuman nin o koeta.','Số lượng khách vào cửa vượt hơn 1 triệu người.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(529,532,'最近全然眠れない。','さいきんぜんぜんねむれない。','Saikin zenzen nemurenai.','Dạo này tôi chẳng thể ngủ được.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(530,533,'息子の合格を祈る。','むすこのごうかくをいのる。','Musuko no goukaku o inoru.','Cầu nguyện cho đứa con trai thi đỗ.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(531,534,'友達の誕生日を祝う。','ともだちのたんじょうびをいわう。','Tomodachi no tanjoubi o iwau.','Ăn mừng sinh nhật bạn.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(532,535,'家族に会えて嬉しさを感じる。','かぞくにあえてうれしさをかんじる。','Kazoku ni aete ureshisa o kanjiru.','Cảm thấy vui khi được gặp gia đình.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(533,536,'駅で道に迷う。','えきでみちにまよう。','Eki de michi ni mayou.','Tôi bị lạc đường ở ga.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(534,537,'最近頭痛に悩んでいる。','さいきんずつうになやんでいる。','Saikin zutsuu ni nayande iru.','Dạo này tôi lo lắng về bệnh đau đầu.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(535,538,'慌てないで落ち着いてください。','あわてないでおちついてください。','Awatenai de ochitsuite kudasai.','Đừng hấp tấp, hãy bình tĩnh.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(536,539,'梅雨が明ける。','つゆがあける。','Tsuyu ga akeru.','Kết thúc mùa mưa.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(537,540,'部屋の中に日が差してきた。','へやのなかにひがさしてきた。','Heya no naka ni hi ga sashite kita.','Mặt trời chiếu sáng vào trong phòng.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(538,541,'座りにくいのでイスを交換する。','すわりにくいのでいすをこうかんする。','Suwarinikui node isu o koukan suru.','Đổi ghế vì khó ngồi.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(539,542,'今年はこのブランドが流行している。','ことしはこのぶらんどがりゅうこうしている。','Kotoshi wa kono burando ga ryuukou shite iru.','Năm nay thương hiệu này đang thịnh hành.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(540,543,'母にテストの結果を報告する。','ははにてすとのけっかをほうこくする。','Haha ni tesuto no kekka o houkoku suru.','Tôi báo kết quả bài kiểm tra cho mẹ tôi.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(541,544,'アニメを録画する。','あにめをろくがする。','Anime o rokuga suru.','Ghi hình phim hoạt hình.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(542,545,'いつもあの店は混雑している。','いつもあのみせはこんざつしている。','Itsumo ano mise wa konzatsu shite iru.','Cửa hàng đó luôn đông khách.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(543,546,'道路が渋滞しているので、学校に遅れてしまう。','どうろがじゅうたいしているので、がっこうにおくれてしまう。','Douro ga juutai shite iru node, gakkou ni okurete shimau.','Đường đang bị tắc do có tai nạn giao thông nên tôi đi học muộn.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(544,547,'会社で意見の衝突が頻発している。','かいしゃでいけんのしょうとつがひんぱつしている。','Kaisha de iken no shoutotsu ga hinpatsu shite iru.','Đã có các ý kiến xung đột tại công ty.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(545,548,'テストが始まり、緊張する。','てすとがはじまり、きんちょうする。','Tesuto ga hajimari, kinchou suru.','Bắt đầu thi nên tôi cảm thấy căng thẳng.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(546,549,'山田くんは両親の手伝いをする感心な息子だ。','やまだくんはりょうしんのてつだいをするかんしんなむすこだ。','Yamada-kun wa ryoushin no tetsudai o suru kanshin na musuko da.','Yamada là đứa con trai đáng khâm phục khi luôn giúp đỡ bố mẹ.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(547,550,'映画を見てとても感動した。','えいがをみてとてもかんどうした。','Eiga o mite totemo kandou shita.','Rất cảm động khi xem phim.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(548,551,'優勝した選手たちは興奮して大声を出した。','ゆうしょうしたせんしゅたちはこうふんしておおごえをだした。','Yuushou shita senshu-tachi wa koufun shite oogoe o dashita.','Tuyển thủ danh chiến thắng đã gào thét vì phấn khích.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(549,552,'夫婦のトラブルを解決する。','ふうふのとらぶるをかいけつする。','Fuufu no toraburu o kaiketsu suru.','Giải quyết rắc rối vợ chồng.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(550,553,'カギをかけたか最後に確認をする。','かぎをかけたかさいごにかくにんをする。','Kagi o kaketa ka saigo ni kakunin o suru.','Xác nhận lần cuối xem đã khóa cửa chưa.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(551,554,'通勤で電車を利用する。','つうきんででんしゃをりようする。','Tsūkin de densha o riyou suru.','Sử dụng tàu điện đi làm.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(552,555,'社長の話は理解できなかった。','しゃちょうのはなしはりかいできなかった。','Shachou no hanashi wa rikai dekinakatta.','Không lý giải được câu chuyện của giám đốc.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(553,556,'新しい星を発見した。','あたらしいほしをはっけんした。','Atarashii hoshi o hakken shita.','Phát hiện ra ngôi sao mới.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(554,557,'これは100年前に発明された。','これは100ねんまえにはつめいされた。','Kore wa hyaku nen mae ni hatsumei sareta.','Cái này được phát minh 100 năm trước.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(555,558,'雷が落ちて、会社が停電した。','かみなりがおちて、かいしゃがていでんした。','Kaminari ga ochite, kaisha ga teiden shita.','Sấm sét rơi xuống, công ty mất điện.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(556,559,'ベトナム語の本を英語に翻訳する。','べとなむごのほんをえいごにほんやくする。','Betonamugo no hon o eigo ni honyaku suru.','Dịch sách tiếng Việt sang tiếng Anh.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(557,560,'大学で経営について学ぶ。','だいがくでけいえいについてまなぶ。','Daigaku de keiei ni tsuite manabu.','Tôi học về quản trị kinh doanh ở trường đại học.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(558,561,'父に怒られ、反省している。','ちちにおこられ、はんせいしている。','Chichi ni okorare, hansei shite iru.','Bị cha mắng, tôi đang kiểm điểm lại bản thân.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(559,562,'給料前に、節約して生活する。','きゅうりょうまえに、せつやくしてせいかつする。','Kyuuryou mae ni, setsuyaku shite seikatsu suru.','Sống tiết kiệm trước ngày lĩnh lương.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(560,563,'予定通りに実行する。','よていどおりにじっこうする。','Yotei doori ni jikkou suru.','Tiến hành theo dự định.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(561,564,'科学が進歩する。','かがくがしんぽする。','Kagaku ga shinpo suru.','Khoa học tiến bộ.','2025-08-27 00:26:55','2025-08-27 00:26:55'),(562,565,'生活が大きく変化する。','せいかつがおおきくへんかする。','Seikatsu ga ookiku henka suru.','Cuộc sống thay đổi rất nhiều.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(563,566,'子どもの体の発達は早い。','こどものからだのはったつははやい。','Kodomo no karada no hattatsu wa hayai.','Cơ thể trẻ con phát triển nhanh.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(564,567,'娘は演劇で大活躍した。','むすめはえんげきでだいかつやくした。','Musume wa engeki de dai katsuyaku shita.','Con gái tôi hoạt động rất năng nổ trong hội thi thể thao.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(565,568,'友達と速さを競争する。','ともだちとはやさをきょうそうする。','Tomodachi to hayasa o kyousou suru.','Chạy đua với bạn để xem ai nhanh hơn.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(566,569,'母校を応援する。','ぼこうをおうえんする。','Bokou o ouen suru.','Ủng hộ cho trường cũ.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(567,570,'大企業に就職した息子を自慢する。','だいきぎょうにしゅうしょくしたむすこをじまんする。','Daikigyō ni shūshoku shita musuko o jiman suru.','Tự hào về đứa con trai đã xin được việc làm ở công ty lớn.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(568,571,'あきさんと、ゆきさんは仲が悪い。','あきさんと、ゆきさんはなかがわるい。','Aki san to, Yuki san wa naka ga warui.','Mối quan hệ giữa Aki và Yuki không tốt.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(569,572,'くだものの皮をむいて食べる。','くだもののかわをむいてたべる。','Kudamono no kawa o muite taberu.','Gọt vỏ hoa quả rồi ăn.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(570,573,'缶詰を食べる。','かんづめをたべる。','Kandzume o taberu.','Ăn đồ hộp.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(571,574,'海の底にはたくさんの魚がいる。','うみのそこにはたくさんのさかながいる。','Umi no soko ni wa takusan no sakana ga iru.','Có rất nhiều cá bơi dưới đáy biển.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(572,575,'坂を上ったところに学校がある。','さかをのぼったところにがっこうがある。','Saka o nobotta tokoro ni gakkou ga aru.','Trường học nằm ở ngay đoạn leo dốc.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(573,576,'たばこの煙のせいで服が臭くなった。','たばこのけむりのせいでふくがくさくなった。','Tabako no kemuri no sei de fuku ga kusaku natta.','Quần áo bị ám mùi do khói thuốc lá.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(574,577,'灰皿にたくさんのタバコの灰が捨ててある。','はいざらにたくさんのたばこのはいがすててある。','Haizara ni takusan no tabako no hai ga sutete aru.','Có nhiều mẩu thuốc lá bỏ trong gạt tàn.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(575,578,'ここに判を押してください。','ここにはんをおしてください。','Koko ni han o oshite kudasai.','Mời anh chị đóng dấu vào đây ạ.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(576,579,'空港で荷物の番をする。','くうこうでにもつのばんをする。','Kuukou de nimotsu no ban o suru.','Trông hành lý ở sân bay.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(577,580,'生野菜は健康にいい。','なまやさいはけんこうにいい。','Nama yasai wa kenkou ni ii.','Rau sống tốt cho sức khỏe.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(578,581,'野菜の値段が倍になる。','やさいのねだんがばいになる。','Yasai no nedan ga bai ni naru.','Giá rau tăng gấp đôi.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(579,582,'書類に穴をあける。','しょるいにあなをあける。','Shorui ni ana o akeru.','Bấm lỗ vào hồ sơ.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(580,583,'人気店の前に長い列ができている。','にんきてんのまえにながいれつができている。','Ninkiten no mae ni nagai retsu ga dekite iru.','Nơi cửa hàng được ưa thích có hàng dài người xếp.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(581,584,'道の幅がせまいので、通りにくい。','みちのはばがせまいので、とおりにくい。','Michi no haba ga semai node, tooriniku i.','Đường hẹp nên khó đi qua.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(582,585,'偽物の商品を買ってしまった。','にせもののしょうひんをかってしまった。','Nisemono no shouhin o katte shimatta.','Tôi mua phải hàng giả.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(583,586,'彼女とは別の意見を持っている。','かのじょとはべつのいけんをもっている。','Kanojo to wa betsu no iken o motte iru.','Tôi có ý kiến khác với cô ấy.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(584,587,'愛とはなんだろう。','あいとはなんだろう。','Ai to wa nan darou.','Tình yêu là gì?','2025-08-27 00:27:01','2025-08-27 00:27:01'),(585,588,'命を大切にする。','いのちをたいせつにする。','Inochi o taisetsu ni suru.','Coi trọng tính mạng.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(586,589,'休んだわけを話す。','やすんだわけをはなす。','Yasunda wake o hanasu.','Nói lý do nghỉ.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(587,590,'足を組む癖がある。','あしをくむくせがある。','Ashi o kumu kuse ga aru.','Có tật ngồi vắt chân.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(588,591,'本に印を付ける。','ほんにしるしをつける。','Hon ni shirushi o tsukeru.','Đánh dấu vào sách.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(589,592,'日本製品の質はいいと海外の人から言われた。','にほんせいひんのしつはいいとかいがいのひとからいわれた。','Nihon seihin no shitsu wa ii to kaigai no hito kara iwareta.','Chất lượng hàng hóa của Nhật Bản được người nước ngoài đánh giá tốt.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(590,593,'大型のトラックの運転は難しい。','おおがたのとらっくのうんてんはむずかしい。','Oogata no torakku no unten wa muzukashii.','Lái 1 chiếc tải cỡ đại rất khó.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(591,594,'宝くじを引いたら、一等が当たった。','たからくじをひいたら、いっとうがあたった。','Takarakuji o hiitara, ittou ga atatta.','Rút xổ số và trúng giải nhất.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(592,595,'この大会には多くの人が参加した。','このたいかいにはおおくのひとがさんかした。','Kono taikai ni wa ooku no hito ga sanka shita.','Trong đại hội này có nhiều trường tham gia.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(593,596,'山田くんはクラスで一番いじわるだ。','やまだくんはくらすでいちばんいじわるだ。','Yamada-kun wa kurasu de ichiban ijiwaru da.','Yamada xấu tính nhất lớp.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(594,597,'いたずらをして先生に怒られた。','いたずらをしてせんせいにおこられた。','Itazura o shite sensei ni okorareta.','Nghịch ngợm nên bị thầy mắng.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(595,598,'遠くにいる祖母と手紙のやり取りをする。','とおくにいるそぼとてがみのやりとりをする。','Tooku ni iru sobo to tegami no yaritori o suru.','Trao đổi thư từ với người bà sống ở xa.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(596,599,'上司にお礼を言う。','じょうしにおれいをいう。','Joushi ni orei o iu.','Nói lời cảm ơn với cấp trên.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(597,600,'私は３つ年上の兄がいる。','わたしはみっつとしうえのあにがいる。','Watashi wa mittsu toshiue no ani ga iru.','Tôi có 1 người anh trai hơn tôi 3 tuổi.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(598,601,'上目の人には礼儀正しくしなければならない。','めうえのひとにはれいぎただしくしなければならない。','Meue no hito ni wa reigi tadashiku shinakereba naranai.','Cần phải giữ đúng lễ nghĩa với người trên.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(599,602,'休日に上司と温泉旅行をした。','きゅうじつにじょうしとおんせんりょこうをした。','Kyuujitsu ni joushi to onsen ryokou o shita.','Ngày nghỉ tôi đi du lịch suối nước nóng với sếp của công ty.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(600,603,'試合の相手は強そうだ。','しあいのあいてはつよそうだ。','Shiai no aite wa tsuyosou da.','Đối thủ trận đấu này có vẻ mạnh.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(601,604,'この問題は試験の範囲に入っている。','このもんだいはしけんのはんいにはいっている。','Kono mondai wa shiken no han\'i ni haitte iru.','Câu hỏi này nằm trong phạm vi bài kiểm tra.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(602,605,'あの人の話は内容がない。','あのひとのはなしはないようがない。','Ano hito no hanashi wa naiyou ga nai.','Câu chuyện của người đó không có nội dung.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(603,606,'箱の中身を調べる。','はこのなかみをしらべる。','Hako no nakami o shiraberu.','Kiểm tra đồ bên trong hộp.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(604,607,'犯人の特徴を覚える。','はんにんのとくちょうをおぼえる。','Hannin no tokuchou o oboeru.','Nhớ đặc trưng của tên tội phạm.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(605,608,'普通に考えたらすぐ分かる。','ふつうにかんがえたらすぐわかる。','Futsuu ni kangaetara sugu wakaru.','Tôi thấy nếu suy nghĩ theo cách bình thường là sẽ hiểu ngay thôi.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(606,609,'会社には近道をして行きます。','かいしゃにはちかみちをしていきます。','Kaisha ni wa chikamichi o shite ikimasu.','Đi đường tắt để tới công ty.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(607,610,'市の中心に大きなビルがある。','しのちゅうしんにおおきなびるがある。','Shi no chuushin ni ookina biru ga aru.','Ở trung tâm khu phố có tòa nhà lớn.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(608,611,'この辺りは人が少ない。','このあたりはひとがすくない。','Kono atari wa hito ga sukunai.','Xung quanh đây không có nhiều người.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(609,612,'家の周りを歩く。','いえのまわりをあるく。','Ie no mawari o aruku.','Đi bộ xung quanh nhà.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(610,613,'映画の前半だけ見た。','えいがのぜんはんだけみた。','Eiga no zenhan dake mita.','Tôi chỉ xem nửa đầu của bộ phim.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(611,614,'後半もがんばってください。','こうはんもがんばってください。','Kouhan mo ganbatte kudasai.','Hãy cố gắng cả nửa sau nữa nhé.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(612,615,'今日は人生で最高の日だ。','きょうはじんせいでさいこうのひだ。','Kyou wa jinsei de saikou no hi da.','Hôm nay là ngày tuyệt vời nhất trong đời.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(613,616,'今までで最低の点数を出してしまった。','いままででさいていのてんすうをだしてしまった。','Imamade de saitei no tensuu o dashite shimatta.','Tôi có số điểm thấp nhất từ trước đến giờ.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(614,617,'最初に英語を、次に日本語を勉強した。','さいしょにえいごを、つぎににほんごをべんきょうした。','Saisho ni eigo o, tsugi ni nihongo o benkyou shita.','Đầu tiên tôi học tiếng Anh, sau đó học tiếng Nhật.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(615,618,'あの学校の制服がかわいいので入学を決めた。','あのがっこうのせいふくがかわいいのでにゅうがくをきめた。','Ano gakkou no seifuku ga kawaii node nyuugaku o kimeta.','Vì đồng phục của ngôi trường đó dễ thương nên tôi đã quyết định nhập học.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(616,618,'高校を卒業すると、制服を着られなくなる。','こうこうをそつぎょうすると、せいふくをきられなくなる。','Koukou o sotsugyou suru to, seifuku o kirarenaku naru.','Tốt nghiệp cấp 3 rồi sẽ không còn được mặc đồng phục nữa.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(617,619,'洗剤で洋服を洗う。','せんざいでようふくをあらう。','Senzai de youfuku o arau.','Giặt quần áo bằng bột giặt.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(618,619,'洗剤を使い過ぎないように気をつけてください。','せんざいをつかいすぎないようにきをつけてください。','Senzai o tsukaisuginai you ni ki o tsukete kudasai.','Hãy chú ý đừng dùng bột giặt quá nhiều.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(619,620,'災害時に備え、携帯用トイレを用意する。','さいがいじにそなえ、けいたいようトイレをよういする。','Saigaiji ni sonae, keitaiyou toire o youi suru.','Chuẩn bị thiết bị toilet cầm tay phòng khi có thảm họa.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(620,621,'運動には自信がある。','うんどうにはじしんがある。','Undou ni wa jishin ga aru.','Tự tin về khả năng vận động.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(621,621,'失敗してしまい、自信を失った。','しっぱいしてしまい、じしんをうしなった。','Shippai shite shimai, jishin o ushinatta.','Thất bại nên đã mất tự tin.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(622,622,'本を読んだ感想を書く。','ほんをよんだかんそうをかく。','Hon o yonda kansou o kaku.','Viết cảm nhận sau khi đọc cuốn sách.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(623,622,'映画の感想を述べる。','えいがのかんそうをのべる。','Eiga no kansou o noberu.','Nêu lên cảm tưởng về bộ phim.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(624,623,'試合の結果を予想する。','しあいのけっかをよそうする。','Shiai no kekka o yosou suru.','Dự đoán kết quả của trận đấu.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(625,623,'雨が降るという予想があたった。','あめがふるというよそうがあたった。','Ame ga furu to iu yosou ga atatta.','Lời dự đoán trời mưa đã thành sự thực.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(626,624,'社員全員に社内調査を行う。','しゃいんぜんいんにしゃないちょうさをおこなう。','Shain zen\'in ni shanai chousa o okonau.','Tiến hành điều tra nội bộ tại các nhân viên trong công ty.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(627,625,'本の題名を決める。','ほんのだいめいをきめる。','Hon no daimei o kimeru.','Quyết định tiêu đề cho cuốn sách.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(628,626,'条件がいい会社をえらぶ。','じょうけんがいいかいしゃをえらぶ。','Jouken ga ii kaisha o erabu.','Lựa chọn công ty có những điều kiện tốt.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(629,626,'大学卒業が採用条件だ。','だいがくそつぎょうがさいようじょうけんだ。','Daigaku sotsugyou ga saiyou jouken da.','Điều kiện tuyển dụng là phải tốt nghiệp đại học.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(630,627,'今月末の締め切りに間に合わない。','こんげつまつのしめきりにまにあわない。','Kongetsumatsu no shimekiri ni maniawanai.','Không kịp hạn chót cuối tháng này.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(631,627,'先生に宿題の締め切りを延ばしてもらった。','せんせいにしゅくだいのしめきりをのばしてもらった。','Sensei ni shukudai no shimekiri o nobashite moratta.','Được giáo viên cho thêm thời hạn làm bài tập.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(632,628,'申込できる期間は一か月です。','もうしこみできるきかんはいっかげつです。','Moushikomi dekiru kikan wa ikkagetsu desu.','Thời hạn có thể đăng ký là 1 tháng.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(633,628,'工事期間は3年です。','こうじきかんはさんねんです。','Kouji kikan wa sannen desu.','Thời gian thi công là 3 năm.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(634,629,'失敗の原因を調べる。','しっぱいのげんいんをしらべる。','Shippai no genin o shiraberu.','Tìm hiểu nguyên nhân thất bại.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(635,629,'原因不明の病気。','げんいんふめいのびょうき。','Genin fumei no byouki.','Căn bệnh không rõ nguyên nhân.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(636,630,'努力の結果が現れる。','どりょくのけっかがあらわれる。','Doryoku no kekka ga arawareru.','Kết quả của nỗ lực được thể hiện.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(637,630,'試験の結果を先生に聞く。','しけんのけっかをせんせいにきく。','Shiken no kekka o sensei ni kiku.','Hỏi kết quả kỳ thi từ thầy giáo.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(638,631,'友達との関係は強くなったり弱くなったりする。','ともだちとのかんけいはつよくなったりよわくなったりする。','Tomodachi to no kankei wa tsuyoku nattari yowaku nattari suru.','Mối quan hệ với bạn bè sẽ có lúc mạnh, lúc yếu.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(639,631,'あの人は事件に関係している。','あのひとはじけんにかんけいしている。','Ano hito wa jiken ni kankei shite iru.','Người đó có liên quan đến vụ án.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(640,632,'彼女は責任感が強い。','かのじょはせきにんかんがつよい。','Kanojo wa sekininkan ga tsuyoi.','Cô ấy là người có tinh thần trách nhiệm cao.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(641,632,'この失敗はみんなの責任だ。','このしっぱいはみんなのせきにんだ。','Kono shippai wa minna no sekinin da.','Trách nhiệm đối với thất bại này thuộc về mọi người.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(642,633,'机の書類を整える。','つくえのしょるいをととのえる。','Tsukue no shorui o totonoeru.','Sắp xếp lại tài liệu có trên bàn.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(643,633,'先輩に書類を確認してもらった。','せんぱいにしょるいをかくにんしてもらった。','Senpai ni shorui o kakunin shite moratta.','Được tiền bối xác nhận giúp tài liệu.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(644,634,'地震の被害を受ける。','じしんのひがいをうける。','Jishin no higai o ukeru.','Bị thiệt hại do trận động đất.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(645,634,'大雨の被害が出る。','おおあめのひがいがでる。','Ooame no higai ga deru.','Xảy ra thiệt hại do mưa lớn.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(646,635,'近所で殺人事件があった。','きんじょでさつじんじけんがあった。','Kinjo de satsujin jiken ga atta.','Quanh khu vực này xảy ra một vụ án giết người.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(647,635,'警察が事件を解決する。','けいさつがじけんをかいけつする。','Keisatsu ga jiken o kaiketsu suru.','Cảnh sát sẽ giải quyết vụ việc.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(648,636,'最近体の調子がいい。','さいきんからだのちょうしがいい。','Saikin karada no choushi ga ii.','Dạo này tình trạng sức khỏe tốt.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(649,636,'後半戦から調子が上がってきた。','こうはんせんからちょうしがあがってきた。','Kouhansen kara choushi ga agatte kita.','Phong độ lên cao từ nửa sau của trận đấu.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(650,637,'団体客をホテルに案内する。','だんたいきゃくをホテルにあんないする。','Dantai kyaku o hoteru ni annai suru.','Hướng dẫn cho đoàn khách vào khách sạn.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(651,637,'学校は団体行動を重んじる。','がっこうはだんたいこうどうをおもんじる。','Gakkou wa dantai koudou o omonjiru.','Trường học đề cao lối hành động tập thể.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(652,638,'20歳を過ぎると、選挙権がある。','はたちをすぎると、せんきょけんがある。','Hatachi o sugiru to, senkyoken ga aru.','Qua 20 tuổi, công dân sẽ có quyền bầu cử.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(653,639,'毎月税金を納める。','まいつきぜいきんをおさめる。','Maitsuki zeikin o osameru.','Nộp thuế hàng tháng.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(654,639,'家を買うと税金がかかる。','いえをかうとぜいきんがかかる。','Ie o kau to zeikin ga kakaru.','Mua nhà cũng mất tiền thuế.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(655,640,'ベトナムの経済成長率は他国よりも高い。','ベトナムのけいざいせいちょうりつはたこくよりもたかい。','Betonamu no keizai seichouritsu wa takoku yori mo takai.','Tỷ lệ tăng trưởng kinh tế của Việt Nam cao hơn các nước khác.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(656,640,'あの子は全く成長していない。','あのこはまったくせいちょうしていない。','Ano ko wa mattaku seichou shite inai.','Đứa trẻ đó không trưởng thành được chút nào.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(657,641,'息子の成人を祝う。','むすこのせいじんをいわう。','Musuko no seijin o iwau.','Mừng lễ trưởng thành cho con trai.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(658,641,'二十歳になったので、成人式に参加する。','はたちになったので、せいじんしきにさんかする。','Hatachi ni natta node, seijinshiki ni sanka suru.','Vì đã 20 tuổi nên tôi tham dự lễ thành nhân.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(659,642,'JLPTの試験に合格する。','JLPTのしけんにごうかくする。','JLPT no shiken ni goukaku suru.','Đỗ kỳ thi JLPT.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(660,642,'それでは、合格者を発表します。','それでは、ごうかくしゃをはっぴょうします。','Sore de wa, goukakusha o happyou shimasu.','Sau đây xin phép công bố những người thi đỗ.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(661,643,'高校を卒業したあと、大学へ進学する。','こうこうをそつぎょうしたあと、だいがくへしんがくする。','Koukou o sotsugyou shita ato, daigaku e shingaku suru.','Sau khi tốt nghiệp cấp 3 tôi đã học lên đại học.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(662,643,'今年の進学率は去年より高い。','ことしのしんがくりつはきょねんよりたかい。','Kotoshi no shingakuritsu wa kyonen yori takai.','Tỷ lệ học lên năm nay cao hơn so với năm ngoái.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(665,645,'大学四年生は就職活動で忙しい。','だいがくよねんせいはしゅうしょくかつどうでいそがしい。','Daigaku yonensei wa shuushoku katsudou de isogashii.','Sinh viên năm 4 rất bận do phải tìm kiếm việc làm.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(666,645,'景気が悪いので、今年の大学卒業生は就職が難しいだろう。','けいきがわるいので、ことしのだいがくそつぎょうせいはしゅうしょくがむずかしいだろう。','Keiki ga warui node, kotoshi no daigaku sotsugyousei wa shuushoku ga muzukashii darou.','Kinh tế đi xuống nên sinh viên đại học năm nay rất khó khăn trong việc tìm kiếm việc làm.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(668,647,'彼の意見に賛成する人がたくさんいる。','かれのいけんにさんせいするひとがたくさんいる。','Kare no iken ni sansei suru hito ga takusan iru.','Có rất nhiều người đồng ý với ý kiến của anh ta.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(669,647,'私もこの計画に賛成です。','わたしもこのけいかくにさんせいです。','Watashi mo kono keikaku ni sansei desu.','Tôi cũng tán thành với kế hoạch này.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(670,648,'上司の提案に反対する。','じょうしのていあんにはんたいする。','Joushi no teian ni hantai suru.','Tôi phản đối đề xuất của cấp trên.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(671,648,'両親に結婚を反対された。','りょうしんにけっこんをはんたいされた。','Ryoushin ni kekkon o hantai sareta.','Bị bố mẹ phản đối việc kết hôn với anh ấy.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(672,649,'大人になった自分を想像する。','おとなになったじぶんをそうぞうする。','Otona ni natta jibun o souzou suru.','Tưởng tượng ra bản thân khi đã trưởng thành.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(673,649,'子どもの想像力は大人よりずっと豊かだ。','こどものそうぞうりょくはおとなよりずっとゆたかだ。','Kodomo no souzouryoku wa otona yori zutto yutakada.','Khả năng tưởng tượng của trẻ con vượt xa người lớn.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(674,650,'努力の結果、上司に認められた。','どりょくのけっか、じょうしにみとめられた。','Doryoku no kekka, joushi ni mitomerareta.','Nhờ kết quả của sự nỗ lực, tôi đã được cấp trên ghi nhận.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(675,650,'あなたはもっと努力が必要です。','あなたはもっとどりょくがひつようです。','Anata wa motto doryoku ga hitsuyou desu.','Bạn cần phải nỗ lực hơn nữa.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(676,651,'新しい家電製品を買いに行く。','あたらしいかでんせいひんをかいにいく。','Atarashii kaden seihin o kai ni iku.','Đi mua đồ điện gia dụng mới.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(677,651,'日本製品は安心で安全だ。','にほんせいひんはあんしんであんぜんだ。','Nihon seihin wa anshin de anzen da.','Sản phẩm của Nhật vừa an toàn, lại an tâm.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(678,652,'去年より野菜が値上がりする。','きょねんよりやさいがねあがりする。','Kyonen yori yasai ga neagari suru.','Rau tăng giá hơn so với năm ngoái.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(679,652,'魚が値上がりして、なかなか買えない。','さかながねあがりして、なかなかかえない。','Sakana ga neagari shite, nakanaka kaenai.','Cá lên giá nên mãi mà chưa mua nổi.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(680,653,'大変お世話になりました。','たいへんおせわになりました。','Taihen osewa ni narimashita.','Vô cùng cảm ơn anh thời gian qua đã giúp đỡ.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(681,653,'家に帰ったら犬の世話をする。','いえにかえったらいぬのせわをする。','Ie ni kaettara inu no sewa o suru.','Về đến nhà tôi lại chăm chú chó của tôi.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(682,654,'彼女は家庭的だ。','かのじょはかていてきだ。','Kanojo wa katei-teki da.','Cô ấy là con người của gia đình.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(683,654,'あたたかい家庭をつくる。','あたたかいかていをつくる。','Atatakai katei o tsukuru.','Xây dựng một gia đình ấm áp yêu thương.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(684,655,'友達に協力を求める。','ともだちにきょうりょくをもとめる。','Tomodachi ni kyouryoku o motomeru.','Tìm kiếm sự giúp đỡ từ bạn bè.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(685,655,'協力して仕事を仕上げる。','きょうりょくしてしごとをしあげる。','Kyouryoku shite shigoto o shiageru.','Hiệp lực với nhau để hoàn thành công việc.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(686,656,'産んでくれた母に感謝する。','うんでくれたははにかんしゃする。','Unde kureta haha ni kansha suru.','Biết ơn người mẹ đã sinh ra mình.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(687,656,'彼女はとても感謝している。','かのじょはとてもかんしゃしている。','Kanojo wa totemo kansha shite iru.','Cô ấy vô cùng biết ơn.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(688,657,'道でステキな男性に出会った。','みちですてきなだんせいにであった。','Michi de suteki na dansei ni deatta.','Tôi gặp được một người đàn ông tuyệt vời trên đường.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(689,658,'女性には優しくするのが当たり前だ。','じょせいにはやさしくするのがあたりまえだ。','Josei ni wa yasashiku suru no ga atarimae da.','Việc đối xử nhẹ nhàng với phụ nữ là điều đương nhiên.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(690,658,'性格がいい女性と結婚したい。','せいかくがいいじょせいとけっこんしたい。','Seikaku ga ii josei to kekkon shitai.','Tôi đã kết hôn với một người phụ nữ tốt tính.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(691,659,'現在日本は高齢化社会になっている。','げんざいにほんはこうれいかしゃかいになっている。','Genzai Nihon wa koureika shakai ni natte iru.','Hiện nay Nhật Bản đang trở thành một xã hội già hóa dân số.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(692,659,'高齢者には親切に接する。','こうれいしゃにはしんせつにせっする。','Koureisha ni wa shinsetsu ni sessuru.','Cư xử thân thiện với những người cao tuổi.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(693,660,'帰り道で大の知り合いに会った。','かえりみちでだいのしりあいにあった。','Kaerimichi de dai no shiriai ni atta.','Trên đường về tôi đã gặp người quen của chồng.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(694,660,'知り合いを通して、たくさん友達を作る。','しりあいをとおして、たくさんともだちをつくる。','Shiriai o tooshite, takusan tomodachi o tsukuru.','Có thêm được nhiều bạn bè thông qua người quen.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(695,661,'会社の会議に出席する。','かいしゃのかいぎにしゅっせきする。','Kaisha no kaigi ni shusseki suru.','Tham dự vào cuộc họp của công ty.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(696,661,'出席者はこの紙に名前を書いてください。','しゅっせきしゃはこのかみになまえをかいてください。','Shussekisha wa kono kami ni namae o kaite kudasai.','Những người tham dự xin hãy viết tên vào tờ giấy này.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(697,662,'かぜを引いたので、授業を欠席する。','かぜをひいたので、じゅぎょうをけっせきする。','Kaze o hiita node, jugyou o kesseki suru.','Vì bị cảm nên tôi đã vắng mặt ở lớp học.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(698,663,'赤ちゃんは、何にでも興味を持つ。','あかちゃんは、なににでもきょうみをもつ。','Akachan wa, nani ni demo kyoumi o motsu.','Trẻ nhỏ có hứng thú với tất cả mọi thứ.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(699,663,'人の恋愛には興味がない。','ひとのれんあいにはきょうみがない。','Hito no renai ni wa kyoumi ga nai.','Không có hứng thú với chuyện yêu đương trai gái.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(700,664,'彼女とはいい思い出が作れた。','かのじょとはいいおもいでがつくれた。','Kanojo to wa ii omoide ga tsukureta.','Tôi đã có những kỉ niệm đẹp với cô ấy.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(701,664,'昔の思い出は、わすれられない。','むかしのおもいでは、わすれられない。','Mukashi no omoide wa, wasurerarenai.','Không thể quên được những kỉ niệm ngày xưa.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(702,665,'冗談を言ってみんなを笑わせる。','じょうだんをいってみんなをわらわせる。','Joudan o itte minna o warawaseru.','Nói đùa khiến cho mọi người cười.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(703,665,'彼の冗談は全然面白くない。','かれのじょうだんはぜんぜんおもしろくない。','Kare no joudan wa zenzen omoshirokunai.','Anh ta giỡn chẳng hề thú vị chút nào.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(704,666,'スマートフォンの画面を見ると目が疲れる。','すまーとふぉんのがめんをみるとめがつかれる。','Sumaato fon no gamen o miru to me ga tsukareru.','Nếu thường xuyên nhìn màn hình điện thoại thì sẽ mệt mắt.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(705,666,'テレビの画面をタオルでふく。','てれびのがめんをたおるでふく。','Terebi no gamen o taoru de fuku.','Lau màn hình TV bằng khăn.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(706,667,'昨日の事件が新聞記事にのっていた。','きのうのじけんがしんぶんきじにのっていた。','Kinou no jiken ga shinbun kiji ni notte ita.','Vụ việc hôm qua đã được đăng trên báo.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(707,667,'この記事によると、今年は観光客が減りそうだ。','このきじによると、ことしはかんこうきゃくがへりそうだ。','Kono kiji ni yoru to, kotoshi wa kankoukyaku ga herisou da.','Theo bài báo này thì lượng người đi du lịch năm nay sẽ suy giảm.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(708,668,'近所の公園で子どもたちが楽しそうに遊んでいる。','きんじょのこうえんでこどもたちがたのしそうにあそんでいる。','Kinjo no kouen de kodomotachi ga tanoshisou ni asonde iru.','Ở công viên gần nhà, lũ trẻ đang chơi đùa trông rất vui vẻ.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(709,668,'近所の人とはとても仲がいい。','きんじょのひととはとてもなかがいい。','Kinjo no hito to wa totemo naka ga ii.','Rất thân với hàng xóm.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(710,669,'ニュースにでていた犯人を見つけてしまった。','にゅーすにでていたはんにんをみつけてしまった。','Nyuusu ni deteita hannin o mitsukete shimatta.','Tôi đã phát hiện thấy tên tội phạm xuất hiện trên thời sự.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(711,669,'警察が万引きした犯人をつかまえた。','けいさつがまんびきしたはんにんをつかまえた。','Keisatsu ga manbiki shita hannin o tsukamaeta.','Cảnh sát đã bắt giữ tên tội phạm chuyên nhảy đồ ở các cửa hàng.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(712,670,'お会計の時に小銭がないことに気付いた。','おかいけいのときにこぜにがないことにきづいた。','Okaikei no toki ni kozeni ga nai koto ni kizuita.','Khi thanh toán thì mới nhận ra là không có tiền lẻ.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(713,670,'ポケットの中の小銭を落としてしまった。','ぽけっとのなかのこぜにをおとしてしまった。','Poketto no naka no kozeni o otoshite shimatta.','Đã làm rơi mất đồng xu trong túi.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(714,671,'お詫び申し上げます。','おわびもうしあげます。','Owabi moushiagemasu.','Chúng tôi vô cùng xin lỗi.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(715,672,'ていねいにお辞儀をする。','ていねいにおじぎをする。','Teinei ni ojigi o suru.','Cúi chào 1 cách lịch sự.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(716,673,'コンサートでアイドルと握手をする。','こんさーとであいどるとあくしゅをする。','Konsaato de aidoru to akushu o suru.','Bắt tay với thần tượng trong buổi hòa nhạc.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(717,674,'夕方になると太陽が沈みはじめた。','ゆうがたになるとたいようがしずみはじめた。','Yuugata ni naru to taiyou ga shizumi hajimeta.','Hoàng hôn buông xuống, mặt trời bắt đầu lặn.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(718,674,'朝になると太陽が昇り、空の外が明るい。','あさになるとたいようがのぼり、そらのそとがあかるい。','Asa ni naru to taiyou ga nobori, sora no soto ga akarui.','Buổi sáng mặt trời lên cao nên bầu trời sáng bừng lên.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(719,675,'夕方になると温度が下がる。','ゆうがたになるとおんどがさがる。','Yuugata ni naru to ondo ga sagaru.','Đến chiều tối thì nhiệt độ giảm xuống.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(720,675,'エアコンを消したので、部屋の温度が上がった。','えあこんをけしたので、へやのおんどがあがった。','Eakon o keshita node, heya no ondo ga agatta.','Tắt điều hòa nên nhiệt độ phòng tăng lên.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(721,676,'雨がふった後は、湿度が高くなる。','あめがふったあとは、しつどがたかくなる。','Ame ga futta ato wa, shitsudo ga takaku naru.','Sau khi trời mưa thì độ ẩm tăng cao.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(722,676,'今日は湿度が10%で空気がかなり乾いている。','きょうはしつどがじゅっぱーせんとでくうきがかなりかわいている。','Kyou wa shitsudo ga juppaasento de kuuki ga kanari kawaiteru.','Vì hôm nay độ ẩm là 10% nên không khí khô.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(723,677,'この部屋は湿気が多いので窓を開けよう。','このへやはしっけがおおいのでまどをあけよう。','Kono heya wa shikke ga ooi node mado o akeyou.','Vì căn phòng này nhiều hơi ẩm nên mở cửa sổ ra.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(724,677,'今日は湿気が少なく、洗濯物が早くかわきそうだ。','きょうはしっけがすくなく、せんたくものがはやくかわきそうだ。','Kyou wa shikke ga sukunaku, sentakumono ga hayaku kawakisou da.','Hôm nay trời không bị ẩm mấy nên đồ giặt nhanh khô.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(725,678,'6月に入り梅雨の時期がやってきた。','ろくがつにはいりつゆのじきがやってきた。','Rokugatsu ni hairi tsuyu no jiki ga yattekita.','Tháng 6 tới và mùa mưa cũng đến.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(726,678,'梅雨時は毎日のように雨がふるので、かさを持ってでかける。','つゆどきはまいにちのようにあめがふるので、かさをもってでかける。','Tsuyu-doki wa mainichi no you ni ame ga furu node, kasa o motte dekakeru.','Vào mùa mưa hầu như ngày nào cũng mưa nên mang ô theo khi ra ngoài.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(727,679,'部屋にかびが生えないように、湿気を外に逃がす。','へやにかびがはえないように、しっけをそとににがす。','Heya ni kabi ga haenai you ni, shikke o soto ni nigasu.','Thông khí cho hơi ẩm ra ngoài để căn phòng không bị ẩm mốc.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(728,679,'パンにかびが生えてしまい、食べられなくなった。','ぱんにかびがはえてしまい、たべられなくなった。','Pan ni kabi ga haete shimai, taberarenakunatta.','Cái bánh mỳ đã bị mốc nên không ăn được nữa.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(729,680,'冬は寒いので、毎日暖房をつける。','ふゆはさむいので、まいにちだんぼうをつける。','Fuyu wa samui node, mainichi danbou o tsukeru.','Vì mùa đông lạnh nên hằng ngày đều bật lò sưởi.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(730,680,'暖房を消す。','だんぼうをけす。','Danbou o kesu.','Tắt lò sưởi đi.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(731,681,'ここに生年月日を書いてください。','ここにせいねんがっぴをかいてください。','Koko ni seinengappi o kaite kudasai.','Hãy viết ngày tháng năm sinh vào đây.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(732,682,'お誕生日おめでとうございます。','おたんじょうびおめでとうございます。','Otanjoubi omedetou gozaimasu.','Chúc mừng sinh nhật.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(733,682,'新しいアイドルグループが誕生する。','あたらしいあいどるぐるーぷがたんじょうする。','Atarashii aidoru guruupu ga tanjou suru.','Một nhóm nhạc thần tượng mới ra đời.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(734,683,'将来が不安なので失業保険に加入する。','しょうらいがふあんなのでしつぎょうほけんにかにゅうする。','Shourai ga fuan na node shitsugyou hoken ni kanyuu suru.','Lo lắng về tương lai nên tham gia bảo hiểm thất nghiệp.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(735,683,'失業者が増えている。','しつぎょうしゃがふえている。','Shitsugyousha ga fuete iru.','Người thất nghiệp tăng lên mỗi năm.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(736,684,'毎日5時間も残業させられている。','まいにちごじかんもざんぎょうさせられている。','Mainichi gojikan mo zangyou saserarete iru.','Ngày nào cũng bị bắt làm thêm 5 tiếng.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(737,684,'残業代がほしいのでたくさん働く。','ざんぎょうだいがほしいのでたくさんはたらく。','Zangyou-dai ga hoshii node takusan hataraku.','Làm thật nhiều vì muốn có tiền làm thêm.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(738,685,'会社までの通勤時間は1時間以上だ。','かいしゃまでのつうきんじかんはいちじかんいじょうだ。','Kaisha made no tsuukin jikan wa ichijikan ijou da.','Thời gian đi đến công ty là hơn 1 tiếng.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(739,685,'健康のために歩いて通勤する。','けんこうのためにあるいてつうきんする。','Kenkou no tame ni aruite tsuukin suru.','Để tốt cho sức khỏe, tôi đi bộ đi làm.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(740,686,'今は学歴社会となっている。','いまはがくれきしゃかいとなっている。','Ima wa gakureki shakai to natte iru.','Thời đại bây giờ là xã hội coi trọng bằng cấp.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(741,686,'学歴が低いと就職が難しい。','がくれきがひくいとしゅうしょくがむずかしい。','Gakureki ga hikui to shuushoku ga muzukashii.','Bằng cấp thấp thì khó xin việc.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(742,687,'インターネットで商品を注文する。','いんたーねっとでしょうひんをちゅうもんする。','Intaanetto de shouhin o chuumon suru.','Đặt hàng qua internet.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(743,687,'レストランでステーキを注文する。','れすとらんですてーきをちゅうもんする。','Resutoran de suteeki o chuumon suru.','Gọi món bò bít tết ở nhà hàng.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(744,688,'毎月一万円を貯金する。','まいつきいちまんえんをちょきんする。','Maitsuki ichiman en o chokin suru.','Hàng tháng tiết kiệm 1 vạn yên.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(745,688,'銀行に預けた貯金を引き出す。','ぎんこうにあずけたちょきんをひきだす。','Ginkou ni azuketa chokin o hikidasu.','Rút tiền tiết kiệm đã gửi ở ngân hàng.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(746,689,'明日はテストなので、徹夜で勉強する。','あしたはてすとなので、てつやでべんきょうする。','Ashita wa tesuto na node, tetsuya de benkyou suru.','Vì ngày mai có bài kiểm tra nên tôi thức suốt đêm để học.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(747,689,'昨日は徹夜で仕事をしたので、とてもねむい。','きのうはてつやでしごとをしたので、とてもねむい。','Kinou wa tetsuya de shigoto o shita node, totemo nemui.','Hôm qua làm việc suốt đêm nên rất buồn ngủ.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(748,690,'去年より身長が5センチ伸びていた。','きょねんよりしんちょうがごせんちのびていた。','Kyonen yori shinchou ga go-senchi nobite ita.','Chiều cao đã tăng hơn 5 cm so với năm ngoái.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(749,690,'病院で体重と身長を測る。','びょういんでたいじゅうとしんちょうをはかる。','Byouin de taijuu to shinchou o hakaru.','Ở bệnh viện đo cân nặng và chiều cao.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(750,691,'たくさん食べすぎて、体重が増えた。','たくさんたべすぎて、たいじゅうがふえた。','Takusan tabe sugite, taijuu ga fueta.','Ăn quá nhiều nên đã tăng cân.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(751,691,'医者に体重を減らすように運動するように言われた。','いしゃにたいじゅうをへらすようにうんどうするようにいわれた。','Isha ni taijuu o herasu you ni undou suru you ni iwareta.','Bác sĩ dặn tôi phải tập thể dục để giảm cân.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(752,692,'遠慮せずに食べてください。','えんりょせずにたべてください。','Enryo sezu ni tabete kudasai.','Xin đừng ngại ngần, hãy cứ ăn đi.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(753,692,'ここの飲食はご遠慮ください。','ここのいんしょくはごえんりょください。','Koko no inshoku wa go-enryo kudasai.','Xin đừng ăn uống ở đây. (hãy biết ý tứ)','2025-08-27 00:27:07','2025-08-27 00:27:07'),(754,693,'この男はとても我慢強い性格だ。','このおとこはとてもがまんづよいせいかくだ。','Kono otoko wa totemo gaman-zuyoi seikaku da.','Con trai trường là người có tính cách kiên nhẫn.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(755,693,'彼にはもう我慢ができない。','かれにはもうがまんができない。','Kare ni wa mou gaman ga dekinai.','Tôi không thể chịu đựng anh ấy thêm nữa.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(756,694,'家に帰ったら、化粧を落とす。','いえにかえったら、けしょうをおとす。','Ie ni kaettara, keshou o otosu.','Về nhà xong thì tẩy trang.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(757,694,'デートをする時は、しっかりと化粧をする。','でーとをするときは、しっかりとけしょうをする。','Deeto o suru toki wa, shikkari to keshou o suru.','Khi hẹn hò thì trang điểm cẩn thận.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(758,695,'先生と面接試験の練習をする。','せんせいとめんせつしけんのれんしゅうをする。','Sensei to mensetsu shiken no renshuu o suru.','Luyện tập phỏng vấn thi với giáo viên.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(759,695,'面接で緊張のあまり、上手く話せなかった。','めんせつできんちょうのあまり、うまくはなせなかった。','Mensetsu de kinchou no amari, umaku hanasenakatta.','Tôi đã không thể nói trôi chảy vì hồi hộp trong buổi phỏng vấn.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(760,696,'この店は観光客でにぎわっている。','このみせはかんこうきゃくでにぎわっている。','Kono mise wa kankoukyaku de nigiwatte iru.','Cửa hàng này rất náo nhiệt vì khách tham quan.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(761,696,'東京の観光地に行くのが楽しみだ。','とうきょうのかんこうちにいくのがたのしみだ。','Toukyou no kankouchi ni iku no ga tanoshimi da.','Háo hức mong chờ việc được đi đến những khu tham quan ở Tokyo.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(762,697,'平日は毎日5時に帰宅する。','へいじつはまいにちごじにきたくする。','Heijitsu wa mainichi goji ni kitaku suru.','Ngày thường thì tôi sẽ về nhà lúc 5 giờ chiều.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(763,697,'帰宅が遅くなり、妻に文句を言われた。','きたくがおそくなり、つまにもんくをいわれた。','Kitaku ga osoku nari, tsuma ni monku o iwareta.','Bị vợ mắng là “sao anh về nhà muộn thế?”.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(764,698,'会計をするときに全部を計算する。','かいけいをするときにぜんぶをけいさんする。','Kaikei o suru toki ni zenbu o keisan suru.','Tính giá tiền khi thanh toán.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(765,698,'こんな方法だと時間がかかりすぎて計算が面倒だ。','こんなほうほうだとじかんがかかりすぎてけいさんがめんどうだ。','Konna houhou da to jikan ga kakarisugite keisan ga mendou da.','Mất thời gian với những phép tính đơn giản.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(766,699,'友達と旅行の計画を立てる。','ともだちとりょこうのけいかくをたてる。','Tomodachi to ryokou no keikaku o tateru.','Lên kế hoạch đi du lịch với bạn.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(767,699,'冬休みは北海道でスキーをする計画を立てている。','ふゆやすみはほっかいどうでスキーをするけいかくをたてている。','Fuyuyasumi wa Hokkaidou de sukii o suru keikaku o tatete iru.','Tôi đang lên kế hoạch đi trượt tuyết ở Hokkaido vào kỳ nghỉ đông.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(768,700,'ビジネスで大成功をする。','びじねすでだいせいこうをする。','Bijinesu de daiseikou o suru.','Thành công lớn trong kinh doanh.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(769,700,'成功した人の話を聞く。','せいこうしたひとのはなしをきく。','Seikou shita hito no hanashi o kiku.','Nghe câu chuyện của người thành công.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(770,701,'あと一歩で目的地に着きます。','あといっぽでもくてきちにつきます。','Ato ippo de mokutekichi ni tsukimasu.','Chỉ còn một chút nữa là tới đích.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(771,701,'目的を持って勉強すると上達しやすい。','もくてきをもってべんきょうするとじょうたつしやすい。','Mokuteki o motte benkyou suru to joutatsu shiyasui.','Học có mục đích thì sẽ dễ tiến bộ hơn.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(772,702,'恋人との約束を守ってしまった。','こいびととのやくそくをまもってしまった。','Koibito to no yakusoku o mamotte shimatta.','Tôi đã giữ lời hứa với người yêu.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(773,702,'約束したのに彼は来なかった。','やくそくしたのにかれはこなかった。','Yakusoku shita noni kare wa konakatta.','Dù đã hứa nhưng anh ấy không đến.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(774,703,'入学希望者を集める。','にゅうがくきぼうしゃをあつめる。','Nyuugaku kibousha o atsumeru.','Tập trung những thí sinh có nguyện vọng nhập học.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(775,703,'東京での就職を希望している。','とうきょうでのしゅうしょくをきぼうしている。','Toukyou de no shuushoku o kibou shite iru.','Mong muốn tìm kiếm việc làm tại Tokyo.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(776,704,'この料理を作ったが、失敗してしまった。','このりょうりをつくったが、しっぱいしてしまった。','Kono ryouri o tsukutta ga, shippai shite shimatta.','Tôi đã làm món này nhưng hỏng mất rồi.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(777,704,'大学の入学試験に失敗する。','だいがくのにゅうがくしけんにしっぱいする。','Daigaku no nyuugaku shiken ni shippai suru.','Tôi đã thi trượt kỳ thi vào đại học.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(778,705,'机の上の書類を整理する。','つくえのうえのしょるいをせいりする。','Tsukue no ue no shorui o seiri suru.','Sắp xếp lại bàn làm việc và sắp xếp tài liệu.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(779,705,'整理して要らないものを捨てる。','せいりしていらないものをすてる。','Seiri shite iranai mono o suteru.','Sắp xếp và vứt bỏ những đồ không cần thiết.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(780,706,'休日は道路がこむ。','きゅうじつはどうろがこむ。','Kyuujitsu wa douro ga komu.','Ngày nghỉ đường rất đông.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(781,706,'道路上に、猫が寝ている。','どうろじょうに、ねこがねている。','Dourojou ni, neko ga nete iru.','Con mèo ngủ trên đường.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(782,707,'となりの人がおしゃべりしていて、先生の話が聞こえない。','となりのひとがおしゃべりしていて、せんせいのはなしがきこえない。','Tonari no hito ga oshaberi shite ite, sensei no hanashi ga kikoenai.','Người bên cạnh cứ nói chuyện khiến tôi không nghe thầy giảng.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(783,707,'あの子は、おしゃべりで、少しうるさい。','あのこは、おしゃべりで、すこしうるさい。','Ano ko wa, oshaberi de, sukoshi urusai.','Con bé đó lắm chuyện nên hơi phiền phức chút.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(784,708,'外で若者がうるさくて、迷惑だ。','そとでわかものがうるさくて、めいわくだ。','Soto de wakamono ga urusakute, meiwaku da.','Thanh niên bên ngoài ồn ào quá, thật là phiền phức.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(785,708,'両親には迷惑をかけてばかりで、申し訳ない。','りょうしんにはめいわくをかけてばかりで、もうしわけない。','Ryoushin ni wa meiwaku o kakete bakari de, moushiwakenai.','Cảm thấy có lỗi vì suốt ngày làm phiền bố mẹ.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(786,709,'日本の東京は大都市だ。','にほんのとうきょうはだいとしだ。','Nihon no Toukyou wa daitoshi da.','Tokyo của Nhật Bản là một đại đô thị.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(787,709,'一つの都市に、多くの中小企業と人口が集まる。','ひとつのとしに、おおくのちゅうしょうきぎょうとじんこうがあつまる。','Hitotsu no toshi ni, ooku no chuushou kigyou to jinkou ga atsumaru.','Nhiều người tập trung ở một thành phố khiến dân số tăng lên.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(788,710,'明日から、地方に転勤になる。','あしたから、ちほうにてんきんになる。','Ashita kara, chihou ni tenkin ni naru.','Từ ngày mai sẽ chuyển công tác về địa phương.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(789,710,'弟は地方から東京に来て働いている。','おとうとはちほうからとうきょうにきてはたらいている。','Otouto wa chihou kara Toukyou ni kite hataraite iru.','Em trai tôi từ địa phương lên Tokyo làm việc.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(790,711,'東洋の料理はとてもおいしい。','とうようのりょうりはとてもおいしい。','Touyou no ryouri wa totemo oishii.','Món ăn của phương Đông rất ngon.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(791,711,'東洋文化を取り入れる。','とうようぶんかをとりいれる。','Touyou bunka o toriireru.','Tiếp thu văn hóa phương Đông.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(792,712,'西洋人は背が高い人が多い。','せいようじんはせがたかいひとがおおい。','Seiyoujin wa sega takai hito ga ooi.','Nhiều người phương Tây có chiều cao.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(793,712,'この建物は西洋風につくられている。','このたてものはせいようふうにつくられている。','Kono tatemono wa seiyou-fuu ni tsukurarete iru.','Tòa nhà này được xây dựng theo phong cách phương Tây.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(794,713,'弟は国際結婚をした。','おとうとはこくさいけっこんをした。','Otouto wa kokusai kekkon o shita.','Em trai tôi đã kết hôn với người nước ngoài.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(795,713,'この問題は国際問題にまで発展した。','このもんだいはこくさいもんだいにまではってんした。','Kono mondai wa kokusai mondai ni made hatten shita.','Vấn đề này đã phát triển thành vấn đề mang tầm quốc tế.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(796,714,'海や川では、自然の中で遊ぶ。','うみやかわでは、しぜんのなかであそぶ。','Umi ya kawa de wa, shizen no naka de asobu.','Đi ra sông, ra biển để được chơi đùa giữa thiên nhiên.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(797,714,'人間は自然の一部であることを忘れてはいけない。','にんげんはしぜんのいちぶであることをわすれてはいけない。','Ningen wa shizen no ichibu de aru koto o wasurete wa ikenai.','Con người không được phép quên rằng mình cũng là một phần của tự nhiên.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(798,715,'ここの景色はとてもきれいだ。','ここのけしきはとてもきれいだ。','Koko no keshiki wa totemo kirei da.','Khung cảnh nhìn từ đây thực sự rất đẹp.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(799,715,'イタリアの景色はすばらしいと感じた。','いたりあのけしきはすばらしいとかんじた。','Itaria no keshiki wa subarashii to kanjita.','Các thị trấn của Italia có cảnh sắc thật tuyệt vời.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(800,716,'世界中にはたくさんの宗教がある。','せかいじゅうにはたくさんのしゅうきょうがある。','Sekaijuu ni wa takusan no shuukyou ga aru.','Có rất nhiều tôn giáo trên khắp thế giới.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(801,716,'宗教によって習慣や考え方が違う。','しゅうきょうによってしゅうかんやかんがえかたがちがう。','Shuukyou ni yotte shuukan ya kangaekata ga chigau.','Người theo tôn giáo khác nhau có tập quán và lối nghĩ khác nhau.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(802,717,'新しいスマートフォンに注目が集まる。','あたらしいすまーとふぉんにちゅうもくがあつまる。','Atarashii sumaatofon ni chuumoku ga atsumaru.','Chiếc điện thoại thông minh mới đã thu hút được sự quan tâm.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(803,717,'彼女はとてもきれいなので、注目を浴びる。','かのじょはとてもきれいなので、ちゅうもくをあびる。','Kanojo wa totemo kirei na node, chuumoku o abiru.','Vì cô ấy rất xinh đẹp nên thu hút sự chú ý của mọi người.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(804,718,'日本語とベトナム語の通訳をする。','にほんごとべとなむごのつうやくをする。','Nihongo to Betonamugo no tsuuyaku o suru.','Phiên dịch giữa tiếng Việt và tiếng Nhật.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(805,718,'将来は通訳の仕事をしたい。','しょうらいはつうやくのしごとをしたい。','Shourai wa tsuuyaku no shigoto o shitai.','Tương lai tôi sẽ làm công việc phiên dịch.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(806,719,'勝利者に拍手を送る。','しょうりしゃにはくしゅをおくる。','Shourisha ni hakushu o okuru.','Gửi 1 tràng pháo tay đến nhà vô địch.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(807,719,'卒業生を拍手で迎える。','そつぎょうせいをはくしゅでむかえる。','Sotsugyousei o hakushu de mukaeru.','Đón khách bằng 1 tràng vỗ tay.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(808,720,'ここにおばけが出るといううわさがある。','ここにおばけがでるといううわさがある。','Koko ni obake ga deru to iu uwasa ga aru.','Người ta đồn ở đây có ma.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(809,720,'その噂は学校中に広まっている。','そのうわさはがっこうじゅうにひろまっている。','Sono uwasa wa gakkoujuu ni hiromatte iru.','Đang lan truyền tin đồn là trường học sẽ không còn nữa.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(810,721,'新商品の宣伝をする。','しんしょうひんのせんでんをする。','Shin shouhin no senden o suru.','Tuyên truyền, quảng bá sản phẩm mới.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(811,722,'不参加の人に伝言をする。','ふさんかのひとにでんごんをする。','Fusanka no hito ni dengon o suru.','Truyền đạt lại cho những người không tham gia.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(812,722,'息子に伝言を残す。','むすこにでんごんをのこす。','Musuko ni dengon o nokosu.','Để lại lời nhắn cho con trai.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(813,723,'年を取ると体力が落ちる。','としをとるとたいりょくがおちる。','Toshi o toru to tairyoku ga ochiru.','Có tuổi rồi thì thể lực cũng giảm sút.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(814,723,'運動すると、体力がつく。','うんどうすると、たいりょくがつく。','Undou suru to tairyoku ga tsuku.','Vận động thì thể lực sẽ được tăng lên.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(815,724,'サッカーの試合に出場する。','さっかーのしあいにしゅつじょうする。','Sakkaa no shiai ni shutsujou suru.','Tham gia trận đấu bóng đá.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(816,724,'県大会に出場する。','けんたいかいにしゅつじょうする。','Ken taikai ni shutsujou suru.','Tham gia đại hội cấp tỉnh.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(817,725,'今回の記録は、今までで一番良かった。','こんかいのきろくはいままででいちばんよかった。','Konkai no kiroku wa ima made de ichiban yokatta.','Kỷ lục lần này là tốt nhất từ trước đến nay.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(818,725,'世界新記録を達成する。','せかいしんきろくをたっせいする。','Sekai shin kiroku o tassei suru.','Xuất hiện kỷ lục mới trên thế giới.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(819,726,'父は健康状態が良くない。','ちちはけんこうじょうたいがよくない。','Chichi wa kenkou joutai ga yokunai.','Tình trạng sức khỏe của bố không tốt.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(820,726,'会社の経営状態は安定している。','かいしゃのけいえいじょうたいはあんていしている。','Kaisha no keiei joutai wa antei shite iru.','Tình hình kinh doanh của công ty rất tốt.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(821,727,'昨日の出来事を友達に話す。','きのうのできごとをともだちにはなす。','Kinou no dekigoto o tomodachi ni hanasu.','Nói cho bạn bè nghe những việc xảy ra hôm qua.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(822,727,'毎日の出来事を日記に書く。','まいにちのできごとをにっきにかく。','Mainichi no dekigoto o nikki ni kaku.','Ghi chép lại những sự kiện hằng ngày vào nhật ký.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(823,728,'あのアニメの名場面は人気だ。','あのあにめのめいばめんはにんきだ。','Ano anime no meibamen wa ninki da.','Khung cảnh nổi tiếng trong bộ phim hoạt hình đó được yêu thích.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(824,728,'事故の場面を見てしまった。','じこのばめんをみてしまった。','Jiko no bamen o mite shimatta.','Tôi thấy hiện trường xảy ra vụ tai nạn.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(825,729,'機会があれば会いましょう。','きかいがあればあいましょう。','Kikai ga areba aimashou.','Nếu có cơ hội thì gặp nhau nhé!','2025-08-27 00:27:07','2025-08-27 00:27:07'),(826,729,'もう一度機会をください。','もういちどきかいをください。','Mou ichido kikai o kudasai.','Hãy cho tôi thêm 1 cơ hội nữa.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(827,730,'家から会社まで長い距離がある。','いえからかいしゃまでながいきょりがある。','Ie kara kaisha made nagai kyori ga aru.','Từ nhà đến trường là một quãng đường khá xa.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(828,730,'彼女とは遠い距離で恋愛している。','かのじょとはとおいきょりでれんあいしている。','Kanojo to wa tooi kyori de renai shite iru.','Tôi và cô ấy yêu xa.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(829,731,'会議で同じ提案をする。','かいぎでおなじていあんをする。','Kaigi de onaji teian o suru.','Đưa ra đề xuất giống nhau trong cuộc họp.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(830,731,'部下の提案を採用する。','ぶかのていあんをさいようする。','Buka no teian o saiyou suru.','Lắng nghe đề xuất của cấp dưới.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(831,732,'旅行に行くために、パスポートを申請する。','りょこうにいくために、ぱすぽーとをしんせいする。','Ryokou ni iku tame ni, pasupooto o shinsei suru.','Đăng ký làm hộ chiếu để đi du lịch.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(832,732,'申請書に記入する。','しんせいしょにきにゅうする。','Shinseisho ni kinyuu suru.','Điền vào đơn đăng ký.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(833,733,'本人確認の証明を提示する。','ほんにんかくにんのしょうめいをていじする。','Honnin kakunin no shoumei o teiji suru.','Chuẩn bị giấy tờ tùy thân.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(834,733,'ご本人が確認できるまで待ちます。','ごほんにんがかくにんできるまでまちます。','Go honnin ga kakunin dekiru made machimasu.','Tôi xin phép được xác nhận xem có đúng người hay không.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(835,734,'契約書にサインをする。','けいやくしょにさいんをする。','Keiyakusho ni sain o suru.','Ký vào hợp đồng.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(836,734,'マンションを3年間借りる契約をする。','まんしょんをさんねんかんかりるけいやくをする。','Manshon o san nenkan kariru keiyaku o suru.','Làm hợp đồng thuê chung cư 3 năm.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(837,735,'父の無実を証明する。','ちちのむじつをしょうめいする。','Chichi no mujitsu o shoumei suru.','Chứng minh bố vô tội.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(838,735,'パスポートの証明写真をとる。','ぱすぽーとのしょうめいしゃしんをとる。','Pasupooto no shoumei shashin o toru.','Chụp ảnh chứng minh hộ chiếu.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(839,736,'明日の予定が変更になった。','あしたのよていがへんこうになった。','Ashita no yotei ga henkou ni natta.','Kế hoạch ngày mai đã thay đổi.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(840,736,'進路を変更することにした。','しんろをへんこうすることにした。','Shinro o henkou suru koto ni shita.','Đã quyết định thay đổi hướng đi.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(841,737,'この野菜は長い間保存できる。','このやさいはながいあいだほぞんできる。','Kono yasai wa nagai aida hozon dekiru.','Rau này có thể bảo quản trong thời gian dài.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(842,737,'作った料理を冷凍保存する。','つくったりょうりをれいとうほぞんする。','Tsukutta ryouri o reitou hozon suru.','Bảo quản đông lạnh món ăn đã chế biến.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(843,738,'スマートフォンの画面を保護フィルムで保護する。','すまーとふぉんのがめんをほごふぃるむでほごする。','Sumaato fon no gamen o hogo firumu de hogo suru.','Bảo vệ màn hình điện thoại bằng miếng dán.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(844,738,'月に一度保護者会が行われる。','つきにいちどほごしゃかいがおこなわれる。','Tsuki ni ichido hogosha kai ga okonawareru.','Cuộc họp phụ huynh 1 tháng được tổ chức 1 lần.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(845,739,'巨大な星が発見された。','きょだいなほしがはっけんされた。','Kyodai na hoshi ga hakken sareta.','Một ngôi sao khổng lồ đã được phát hiện.','2025-09-07 10:22:25','2025-09-07 10:22:25'),(846,740,'巨人へ銃を向けました。','きょじんへじゅうをむけました。','Kyojin e juu o mukemashita.','Anh ta đã chĩa súng về phía người khổng lồ.','2025-09-07 10:22:26','2025-09-07 10:22:26'),(847,741,'貧しい国へ巨額の寄付をする。','まずしいくにへきょがくのきふをする。','Mazushii kuni e kyogaku no kifu o suru.','Quyên góp một số tiền khổng lồ cho quốc gia nghèo.','2025-09-07 10:22:26','2025-09-07 10:22:26'),(848,742,'難民の受け入れを拒む。','なんみんのうけいれをこばむ。','Nanmin no ukeire o kobamu.','Từ chối tiếp nhận người tị nạn.','2025-09-07 10:22:26','2025-09-07 10:22:26'),(849,743,'彼女は、お金がかかるからと言って検査を拒否している。','かのじょは、おかねがかかるからといってけんさをきょひしている。','Kanojo wa, okane ga kakaru kara to itte kensa o kyohi shite iru.','Cô ấy nói là tốn tiền nên đang từ chối kiểm tra.','2025-09-07 10:22:26','2025-09-07 10:22:26'),(850,744,'彼は、両親とのかかわりを拒絶して、家を出ることにした。','かれは、りょうしんとのかかわりをきょぜつして、いえをでることにした。','Kare wa, ryoushin to no kakawari o kyozetsu shite, ie o deru koto ni shita.','Anh ấy cự tuyệt mối liên hệ với bố mẹ và quyết định rời nhà đi.','2025-09-07 10:22:26','2025-09-07 10:22:26'),(851,745,'長距離マラソンランナー。','ちょうきょりマラソンランナー。','Choukyori marason rannaa.','Vận động viên marathon đường dài.','2025-09-07 10:22:26','2025-09-07 10:22:26'),(852,746,'週末、予定入ってる？','しゅうまつ、よていはいってる？','Shuumatsu, yotei haitteru?','Cuối tuần, bạn có kế hoạch gì không?','2025-09-08 01:40:48','2025-09-08 01:40:48'),(853,747,'天気予報によると、明日雪が降るらしい。','てんきよほうによると、あしたゆきがふるらしい。','Tenki yohou ni yoru to, ashita yuki ga furu rashii.','Theo dự báo thời tiết, ngày mai có vẻ sẽ có tuyết.','2025-09-08 01:40:48','2025-09-08 01:40:48'),(854,748,'全然予習ができていない。','ぜんぜんよしゅうができていない。','Zenzen yoshuu ga dekite inai.','Hoàn toàn chưa chuẩn bị bài trước.','2025-09-08 01:40:48','2025-09-08 01:40:48'),(855,749,'息子は予備校の勉強で、毎日朝から夜まで忙しい。','むすこはよびこうのべんきょうで、まいにちあさからよるまでいそがしい。','Musuko wa yobikou no benkyou de, mainichi asa kara yoru made isogashii.','Con trai tôi bận rộn học ở trường dự bị, từ sáng đến tối mỗi ngày.','2025-09-08 01:40:48','2025-09-08 01:40:48'),(856,750,'本を順序よく並べる。','ほんをじゅんじょよくならべる。','Hon o junjo yoku naraberu.','Sắp xếp sách theo đúng thứ tự.','2025-09-08 01:40:49','2025-09-08 01:40:49'),(857,751,'卒業論文の序章を書く。','そつぎょうろんぶんのじょしょうをかく。','Sotsugyou ronbun no joshou o kaku.','Viết chương mở đầu của luận văn tốt nghiệp.','2025-09-08 01:40:49','2025-09-08 01:40:49'),(858,752,'昔使っていた預金通帳を発見しました。','むかしつかっていたよきんつうちょうをはっけんしました。','Mukashi tsukatte ita yokin tsuuchou o hakken shimashita.','Tôi đã phát hiện ra cuốn sổ tiết kiệm từng dùng ngày xưa.','2025-09-08 01:40:49','2025-09-08 01:40:49'),(859,753,'英語は易しい。','えいごはやさしい。','Eigo wa yasashii.','Tiếng Anh thì dễ.','2025-09-08 01:44:07','2025-09-08 01:44:07'),(860,754,'友達の宿題をコピーするなんて安易な考えでは、知識は身につかない。','ともだちのしゅくだいをコピーするなんてあんいなかんがえでは、ちしきはみにつかない。','Tomodachi no shukudai o kopii suru nante ani na kangae de wa, chishiki wa mi ni tsukanai.','Việc chép bài tập của bạn bè là suy nghĩ dễ dãi, sẽ không tích lũy được kiến thức.','2025-09-08 01:44:07','2025-09-30 20:22:48'),(861,755,'貿易の歴史を学んでいる。','ぼうえきのれきしをまなんでいる。','Boueki no rekishi o manande iru.','Tôi đang học về lịch sử mậu dịch.','2025-09-08 01:44:07','2025-09-08 01:44:07'),(862,756,'お湯が出ない。','おゆがでない。','Oyu ga denai.','Không có nước nóng chảy ra.','2025-09-08 01:44:07','2025-09-08 01:44:07'),(863,757,'熱湯風呂に入る。','ねっとうぶろにはいる。','Nettou buro ni hairu.','Vào bồn tắm nước sôi.','2025-09-08 01:44:07','2025-09-08 01:44:07'),(864,758,'陽気な人と話すのが大好きです。','ようきなひととはなすのがだいすきです。','Youki na hito to hanasu no ga daisuki desu.','Tôi rất thích nói chuyện với người vui vẻ.','2025-09-08 01:44:08','2025-09-08 01:44:08'),(865,759,'タバコを吸うのは体に良くない。','たばこをすうのはからだによくない。','Tabako o suu no wa karada ni yokunai.','Hút thuốc lá không tốt cho cơ thể.','2025-09-08 01:46:37','2025-09-08 01:46:37'),(866,760,'あのレストランはとても良心的なお店です。','あのレストランはとてもりょうしんてきなおみせです。','Ano resutoran wa totemo ryoushinteki na omise desu.','Nhà hàng đó là một cửa hàng rất có lương tâm, hợp lý.','2025-09-08 01:46:37','2025-09-08 01:46:37'),(867,761,'娘は留学したがっている。','むすめはりゅうがくしたがっている。','Musume wa ryuugaku shitagatte iru.','Con gái tôi muốn đi du học.','2025-09-08 01:46:37','2025-09-08 01:46:37'),(868,762,'この森には狼がいる。','このもりにはおおかみがいる。','Kono mori ni wa ookami ga iru.','Trong khu rừng này có sói.','2025-09-08 01:46:37','2025-09-08 01:46:37'),(869,763,'スマートフォンは全世界に普及し、私たちの生活に必要なものとなった。','すまーとふぉんはぜんせかいにふきゅうし、わたしたちのせいかつにひつようなものとなった。','Sumaato fon wa zensekai ni fukyuu shi, watashitachi no seikatsu ni hitsuyou na mono to natta.','Điện thoại thông minh đã phổ cập toàn thế giới và trở thành vật cần thiết trong đời sống của chúng ta.','2025-09-08 01:48:05','2025-09-08 01:48:05'),(870,764,'増税は先程の会見で消費者に大きな影響を及ぼす問題だと言われた。','ぞうぜいはさきほどのかいけんでしょうひしゃにおおきなえいきょうをおよぼすもんだいだといわれた。','Zouzei wa sakihodo no kaiken de shouhisha ni ookina eikyou o oyobosu mondai da to iwareta.','Việc tăng thuế vừa được nói trong buổi họp báo là vấn đề gây ảnh hưởng lớn đến người tiêu dùng.','2025-09-08 01:48:05','2025-09-08 01:48:05'),(871,765,'あの車、高級車らしいですね。','あのくるま、こうきゅうしゃらしいですね。','Ano kuruma, koukyuusha rashii desu ne.','Nghe nói chiếc xe đó là xe cao cấp nhỉ.','2025-09-08 01:48:05','2025-09-08 01:48:05'),(872,766,'韓国語の初級を学んでいる。','かんこくごのしょきゅうをまなんでいる。','Kankokugo no shokyuu o manande iru.','Tôi đang học tiếng Hàn sơ cấp.','2025-09-08 01:48:05','2025-09-08 01:48:05'),(873,767,'中級から学ぶという本がある。','ちゅうきゅうからまなぶというほんがある。','Chuukyuu kara manabu to iu hon ga aru.','Có cuốn sách tên là \'Học từ trung cấp\'.','2025-09-08 01:48:05','2025-09-08 01:48:05'),(874,768,'このタバコは太いので、タピオカも吸って飲むことができる。','このたばこはふといので、たぴおかもすってのむことができる。','Kono sutoro wa futoi node, tapioka mo sutte nomu koto ga dekiru.','Ống hút này to nên cũng có thể hút trân châu để uống.','2025-09-08 01:48:05','2025-09-08 01:48:05'),(875,769,'集中力が切れて来たなら、深呼吸をしてみましょう。','しゅうちゅうりょくがきれてきたなら、しんこきゅうをしてみましょう。','Shuuchuuryoku ga kirete kita nara, shinkokyuu o shite mimashou.','Nếu mất tập trung thì hãy thử hít thở sâu.','2025-09-08 01:48:05','2025-09-08 01:48:05'),(876,770,'植物は根から水分を吸収する。','しょくぶつはねからすいぶんをきゅうしゅうする。','Shokubutsu wa ne kara suibun o kyuushuu suru.','Thực vật hấp thụ nước từ rễ.','2025-09-08 01:48:05','2025-09-08 01:48:05'),(877,771,'クラジは仕事を求めて永く。','くらじはしごとをもとめてながく。','Kuraji wa shigoto o motomete nagaku.','Kuraji cầu xin công việc.','2025-09-08 01:50:52','2025-09-08 01:50:52'),(878,772,'支払いを請求する。','しはらいをせいきゅうする。','Shiharai o seikyuu suru.','Yêu cầu thanh toán.','2025-09-08 01:50:52','2025-09-08 01:50:52'),(879,773,'人々は多くの幸福を追求している。','ひとびとはおおくのこうふくをついきゅうしている。','Hitobito wa ooku no koufuku o tsuikyuu shite iru.','Con người đang theo đuổi nhiều hạnh phúc.','2025-09-08 01:50:52','2025-09-08 01:50:52'),(880,774,'球技大会に参加するつもりです。','きゅうぎたいかいにさんかするつもりです。','Kyuugi taikai ni sanka suru tsumori desu.','Tôi định tham gia đại hội thể thao bóng.','2025-09-08 01:50:52','2025-09-08 01:50:52'),(881,775,'地球温暖化を防ぐ。','ちきゅうおんだんかをふせぐ。','Chikyuu ondanka o fusegu.','Ngăn chặn hiện tượng nóng lên toàn cầu.','2025-09-08 01:50:52','2025-09-08 01:50:52'),(882,776,'人が倒れていたから救急車を呼んだ。','ひとがたおれ