INSERT INTO `jp_hanviet` VALUES (1,1,'CHIẾT','Tự động từ, chỉ sự gãy do tác động.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(2,2,'CHIẾT','Tha động từ, chỉ hành động bẻ, làm gãy vật.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(3,3,'ĐẢO','Tự động từ, chỉ sự ngã, đổ, hoặc suy sụp.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(4,4,'ĐẢO','Tha động từ, làm cho ngã hoặc đánh bại đối thủ.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(5,5,'PHÁ','Tự động từ, chỉ đồ vật tự bị rách.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(6,6,'PHÁ','Tha động từ, hành động xé rách vật gì đó.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(7,7,'KHÚC','Tự động từ, chỉ sự rẽ đường hoặc vật tự cong.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(8,8,'KHÚC','Tha động từ, bẻ hoặc uốn cong.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(9,9,'NGOẠI','Tự động từ, dùng khi nút, cửa, dự đoán bị lệch hoặc sai.','2025-08-25 10:36:16','2025-08-25 10:36:16'),(10,10,'HỌC HIỆU','‘学校’ là từ trình độ N5, mang nghĩa trường học.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(11,11,'TIÊN SINH','‘先生’ là từ trình độ N5, mang nghĩa giáo viên.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(12,12,'HỌC SINH','‘学生’ là từ trình độ N5, mang nghĩa học sinh.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(13,13,'NHẬT BẢN','‘日本’ là từ trình độ N5, mang nghĩa Nhật Bản.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(14,14,'HỮU ĐẠT','‘友達’ là từ trình độ N5, mang nghĩa bạn bè.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(15,15,'THỰC','‘食べる’ là từ trình độ N5, mang nghĩa ăn.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(16,16,'ẨM','‘飲む’ là từ trình độ N5, mang nghĩa uống.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(17,17,'MÃI','‘買う’ là từ trình độ N5, mang nghĩa mua.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(18,18,'HÀNH','‘行く’ là từ trình độ N5, mang nghĩa đi.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(19,19,'LAI','‘来る’ là từ trình độ N5, mang nghĩa đến.','2025-08-26 01:49:40','2025-08-26 01:49:40'),(20,2