25-08-27 00:27:01'),(596,599,'LỄ','Danh từ chỉ lời cảm ơn, sự biết ơn đối với người khác.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(597,600,'NIÊN THƯỢNG','Danh từ chỉ người nhiều tuổi hơn mình.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(598,601,'MỤC THƯỢNG','Người có địa vị cao hơn, vai vế cao hơn trong xã hội.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(599,602,'THƯỢNG TI','Người quản lý, cấp trên trong công việc.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(600,603,'TƯƠNG THỦ','Người mình đang giao tiếp, đối tác hoặc đối thủ.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(601,604,'PHẠM VI','Danh từ chỉ phạm vi hoạt động, giới hạn của sự việc.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(602,605,'NỘI DUNG','Danh từ chỉ nội dung bên trong của sự việc, câu chuyện, bài viết...','2025-08-27 00:27:01','2025-08-27 00:27:01'),(603,606,'TRUNG THÂN','Chỉ phần bên trong, phần ruột, hoặc nội dung của sự vật.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(604,607,'ĐẶC TRƯNG','Điểm nổi bật, đặc điểm phân biệt với những cái khác.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(605,608,'PHỔ THÔNG','Chỉ sự việc, trạng thái diễn ra thông thường, không đặc biệt.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(606,609,'CẬN ĐẠO','Danh từ chỉ con đường đi nhanh hơn, rút ngắn thời gian so với đường chính.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(607,610,'TRUNG TÂM','Danh từ chỉ vị trí trọng yếu, trung tâm của sự vật, sự việc.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(608,611,'BIÊN','Danh từ chỉ khu vực xung quanh, gần nơi đang nói đến.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(609,612,'CHU','Danh từ chỉ phạm vi bao quanh một vật hoặc một khu vực.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(610,613,'TIỀN BÁN','Danh từ chỉ phần đầu tiên của một sự việc, giai đoạn, thời gian.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(611,614,'HẬU BÁN','Danh từ chỉ phần sau, giai đoạn cuối cùng của một sự việc hoặc thời gian.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(612,615,'TỐI CAO','Danh từ/tính từ chỉ mức độ cao nhất, tuyệt vời nhất.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(613,616,'TỐI ĐÊ','Danh từ/tính từ chỉ mức độ thấp nhất, tệ hại nhất.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(614,617,'TỐI SƠ','Danh từ chỉ thời điểm đầu tiên, khởi đầu của sự việc.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(615,618,'CHẾ PHỤC','Danh từ chỉ trang phục giống nhau theo quy định, thường dùng trong trường học hoặc công sở.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(616,619,'TẨY TỄ','Danh từ chỉ các chất dùng để giặt giũ hoặc tẩy rửa như bột giặt, nước rửa chén.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(617,620,'HUỀ ĐỚI','Danh từ chỉ các đồ vật có thể mang theo bên người, phổ biến nhất là điện thoại di động.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(618,621,'TỰ TÍN','Danh từ chỉ sự tin tưởng vào bản thân và khả năng của mình.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(619,622,'CẢM TƯỞNG','Danh từ chỉ cảm nhận, suy nghĩ sau khi trải nghiệm hoặc chứng kiến một việc gì đó.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(620,623,'DỰ TƯỞNG','Danh từ, động từ chỉ việc dự đoán, ước đoán trước một sự việc trong tương lai.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(621,624,'ĐIỀU TRA','Danh từ chỉ việc thu thập thông tin, nghiên cứu, khảo sát, điều tra một vấn đề nào đó.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(622,625,'ĐỀ DANH','Danh từ chỉ tên của một cuốn sách, bài văn, bài hát, tác phẩm…','2025-08-27 00:27:01','2025-08-27 00:27:01'),(623,626,'ĐIỀU KIỆN','Danh từ chỉ những điều khoản, hoàn cảnh, tiêu chuẩn cần thiết để thực hiện hay đạt được một việc gì đó.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(624,627,'ĐẾ THIẾT','Danh từ chỉ thời điểm cuối cùng phải hoàn thành một công việc hay nộp bài.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(625,628,'KỲ GIAN','Danh từ chỉ khoảng thời gian có giới hạn, thời hạn nhất định.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(626,629,'NGUYÊN NHÂN','Danh từ chỉ lý do, nguyên nhân dẫn đến kết quả hay sự việc nào đó.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(627,630,'KẾT QUẢ','Danh từ chỉ kết quả, thành quả sau một quá trình hay nỗ lực.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(628,631,'QUAN HỆ','Danh từ chỉ sự liên hệ, mối quan hệ giữa con người hoặc giữa các sự vật, sự việc.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(629,632,'TRÁCH NHIỆM','Danh từ chỉ trách nhiệm, bổn phận của một người đối với công việc hoặc hành động của mình.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(630,633,'THƯ LOẠI','Danh từ chỉ giấy tờ, tài liệu chính thức, văn bản hành chính.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(631,634,'BỊ HẠI','Danh từ chỉ sự tổn thất, thiệt hại gây ra bởi thiên tai, tai nạn hoặc chiến tranh.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(632,635,'SỰ KIỆN','Danh từ chỉ một vụ việc, sự kiện bất thường, thường liên quan đến tội phạm hoặc tai nạn.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(633,636,'ĐIỀU TỬ','Danh từ chỉ tình trạng, trạng thái của cơ thể, sức khỏe hoặc máy móc, công việc.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(634,637,'ĐOÀN THỂ','Danh từ chỉ một nhóm người tập hợp lại thành đoàn thể, tập thể có cùng mục đích.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(635,638,'TUYỂN CỬ','Danh từ chỉ việc lựa chọn người đại diện thông qua bầu cử chính thức.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(636,639,'THUẾ KIM','Danh từ chỉ tiền thuế mà người dân phải nộp cho nhà nước.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(637,640,'THÀNH TRƯỞNG','Danh từ chỉ sự phát triển, trưởng thành của con người, hoặc sự tăng trưởng kinh tế.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(638,641,'THÀNH NHÂN','Danh từ chỉ người đã đủ tuổi trưởng thành theo quy định (thường là 20 tuổi ở Nhật).','2025-08-27 00:27:01','2025-08-27 00:27:01'),(639,642,'HỢP CÁCH','Danh từ, động từ chỉ việc đỗ đạt trong kỳ thi hoặc được chấp nhận vào một tổ chức.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(640,643,'TIẾN HỌC','Danh từ chỉ việc học lên bậc cao hơn như đại học, cao học.','2025-08-27 00:27:01','2025-08-27 00:27:01'),(642,645,'TỰU CHỨC','Danh từ, động từ chỉ việc tìm và bắt đầu một công việc sau khi tốt nghiệp.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(644,647,'TÁN THÀNH','Danh từ, động từ chỉ sự đồng ý, tán thành một ý kiến, quan điểm hay hành động nào đó.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(645,648,'PHẢN ĐỐI','Danh từ, động từ chỉ sự phản đối, không đồng tình với một ý kiến, quyết định hay hành động nào đó.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(646,649,'TƯỞNG TƯỢNG','Danh từ, động từ chỉ việc hình dung, tưởng tượng ra một sự vật, hiện tượng chưa từng thấy.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(647,650,'NỖ LỰC','Danh từ chỉ sự cố gắng, nỗ lực để đạt được mục tiêu.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(648,651,'CHẾ PHẨM','Danh từ chỉ sản phẩm được chế tạo, sản xuất ra để bán trên thị trường.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(649,652,'TRỊ THƯỢNG','Danh từ, động từ chỉ việc giá cả tăng lên so với trước đó.','2025-08-27 00:27:06','2025-08-27 00:27:06'),(650,653,'THẾ THOẠI','Danh từ chỉ sự chăm sóc, giúp đỡ ai đó trong cuộc sống hoặc công việc.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(651,654,'GIA ĐÌNH','Danh từ chỉ gia đình, tổ ấm nơi sinh sống và gắn bó tình cảm.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(652,655,'HIỆP LỰC','Danh từ, động từ chỉ sự hợp tác, cùng nhau làm việc để đạt mục tiêu.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(653,656,'CẢM TẠ','Danh từ, động từ chỉ sự biết ơn, lòng cảm kích đối với người đã giúp đỡ mình.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(654,657,'NAM TÍNH','Danh từ chỉ nam giới, đàn ông.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(655,658,'NỮ TÍNH','Danh từ chỉ nữ giới, phụ nữ.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(656,659,'CAO LINH','Danh từ chỉ tuổi tác cao, người già.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(657,660,'TRI HỢP','Danh từ chỉ những người đã gặp gỡ, quen biết, không thân thiết như bạn bè.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(658,661,'XUẤT TỊCH','Danh từ, động từ chỉ sự có mặt, tham dự ở một cuộc họp, sự kiện, buổi lễ.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(659,662,'KHIẾM TỊCH','Danh từ, động từ chỉ sự không có mặt ở một nơi cần thiết như lớp học, cuộc họp.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(660,663,'HƯNG VỊ','Danh từ chỉ sự quan tâm, hứng thú, yêu thích đối với một sự vật hay hoạt động nào đó.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(661,664,'TƯ XUẤT','Danh từ chỉ những điều đã trải qua và còn nhớ lại, thường gắn liền với cảm xúc.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(662,665,'NHŨNG ĐÀM','Danh từ chỉ lời nói đùa, chuyện không nghiêm túc nhằm làm vui hoặc trêu ghẹo.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(663,666,'HỌA DIỆN','Danh từ chỉ màn hình hiển thị của điện thoại, TV, máy tính...','2025-08-27 00:27:07','2025-08-27 00:27:07'),(664,667,'KÝ SỰ','Danh từ chỉ thông tin, tin tức, bài viết đăng trên báo chí hoặc tạp chí.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(665,668,'CẬN SỞ','Danh từ chỉ khu vực lân cận, hàng xóm hoặc những người sống gần mình.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(666,669,'PHẠM NHÂN','Danh từ chỉ người phạm tội, gây ra hành vi trái pháp luật.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(667,670,'TIỂU TIỀN','Danh từ chỉ số tiền nhỏ, tiền xu, thường dùng khi thanh toán.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(668,671,'SÁ','Danh từ, động từ chỉ sự xin lỗi, bày tỏ lời xin lỗi với người khác.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(669,672,'TỪ NGHI','Danh từ, động từ chỉ hành động cúi đầu chào theo cách lịch sự trong văn hóa Nhật.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(670,673,'ÁC THỦ','Danh từ, động từ chỉ hành động nắm tay chào hỏi, thể hiện sự thân mật hoặc đồng ý.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(671,674,'THÁI DƯƠNG','Danh từ chỉ mặt trời, ngôi sao chiếu sáng ban ngày.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(672,675,'ÔN ĐỘ','Danh từ chỉ nhiệt độ, mức độ nóng lạnh của không khí, cơ thể hay đồ vật.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(673,676,'THẤP ĐỘ','Danh từ chỉ mức độ ẩm trong không khí, khí hậu.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(674,677,'THẤP KHÍ','Danh từ chỉ hơi ẩm, tình trạng ẩm thấp trong không khí hoặc trong nhà.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(675,678,'MAI VŨ','Danh từ chỉ mùa mưa, khoảng thời gian mưa nhiều trong năm.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(676,679,NULL,'Danh từ chỉ hiện tượng mốc do độ ẩm gây ra, thường xuất hiện trên tường, thực phẩm hay trong phòng kín.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(677,680,'NOÃN PHÒNG','Danh từ chỉ thiết bị, hệ thống dùng để sưởi ấm trong mùa đông.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(678,681,'SINH NIÊN NGUYỆT NHẬT','Danh từ chỉ ngày, tháng, năm sinh của một người.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(679,682,'ĐẢN SINH','Danh từ chỉ việc ra đời, sinh ra đời của con người hay sự vật.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(680,683,'THẤT NGHIỆP','Danh từ, động từ chỉ tình trạng mất việc làm, không có việc làm.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(681,684,'TÀN NGHIỆP','Danh từ, động từ chỉ việc làm việc ngoài giờ hành chính, tăng ca.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(682,685,'THÔNG CẦN','Danh từ, động từ chỉ việc đi từ nhà đến nơi làm việc hằng ngày.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(683,686,'HỌC LỊCH','Danh từ chỉ quá trình học tập, bằng cấp đã đạt được.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(684,687,'CHÚ VĂN','Danh từ, động từ chỉ hành động đặt mua hàng hoặc gọi món ăn trong nhà hàng.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(685,688,'TRỮ KIM','Danh từ, động từ chỉ việc tiết kiệm tiền, để dành tiền cho tương lai.','2025-08-27 00:27:07','2025-08-27 00:27:07'),(686,689,'TRIỆT DẠ','Danh từ, động từ chỉ việc thức suốt đêm, không ngủ để làm việc hay học t