nhất: Không có thứ gì đạt đến mức độ của N.','2026-01-20 03:32:02','2026-01-20 03:32:02'),(2484,2487,NULL,'So sánh nhất (mang tính cảm nhận chủ quan của người nói).','2026-01-20 03:32:02','2026-01-20 03:32:02'),(2485,2488,NULL,'Diễn tả mức độ tối thiểu, thấp nhất.','2026-01-20 03:32:02','2026-01-20 03:32:02'),(2486,2489,NULL,'So sánh hai việc đều không muốn, nhưng thà chọn việc sau còn hơn việc trước.','2026-01-20 03:32:02','2026-01-20 03:32:02'),(2487,2490,NULL,'Diễn tả việc làm quá mức bình thường để đạt mục đích.','2026-01-20 03:32:02','2026-01-20 03:32:02'),(2488,2491,NULL,'Thậm chí làm cả những việc lẽ ra không nên làm.','2026-01-20 03:32:02','2026-01-20 03:32:02'),(2489,2492,NULL,'Dùng thay cho 「は」 để nêu chủ đề trong hội thoại thân mật.','2026-01-20 03:32:02','2026-01-20 03:32:02'),(2490,2493,NULL,'Dùng để giải thích tên riêng hoặc danh từ phía trước.','2026-01-20 03:32:46','2026-01-20 03:32:46'),(2491,2494,NULL,'Dạng văn nói thân mật của 「という」.','2026-01-20 03:32:46','2026-01-20 03:32:46'),(2492,2495,NULL,'Dùng để trích dẫn suy nghĩ hoặc lời nói trong văn nói thân mật (thay cho 「と」).','2026-01-20 05:36:23','2026-01-20 05:36:23'),(2493,2496,NULL,'Dùng để truyền đạt lại thông tin nghe được (Văn nói của 「そうです」).','2026-01-20 05:36:23','2026-01-20 05:36:23'),(2494,2497,NULL,'Nhấn mạnh vào đối tượng, ngay cả đối tượng đó cũng vậy.','2026-01-20 05:36:23','2026-01-20 05:36:23'),(2495,2498,NULL,'Biểu thị sự nhượng bộ trong văn nói (giống 「ても」).','2026-01-20 05:36:23','2026-01-20 05:36:23'),(2496,2499,NULL,'Dùng để xác nhận lại trí nhớ của bản thân hoặc hỏi người nghe về điều mình không nhớ rõ.','2026-01-20 05:36:23','2026-01-20 05:36:23'),(2497,2500,NULL,'Phủ định mạnh mẽ khả năng xảy ra của sự việc.','2026-01-20 05:36:23','2026-01-20 05:36:23'),(2498,2501,NULL,'Đưa ra phỏng đoán nhẹ nhàng, thường mang ý ngạc nhiên hoặc đùa vui.','2026-01-20 05:36:23','2026-01-20 05:36:23'),(2499,2502,NULL,'Dùng để yêu cầu, nhờ vả nhẹ nhàng (thường phụ nữ hoặc người lớn nói với trẻ 